INSERT INTO prompt_seed_library (tier, text, anchor, placeholders, category, angle, requires, anti_repeat_group, snowball_hooks, sort_order) VALUES
INSERT INTO prompt_seed_library (tier, text, anchor, placeholders, category, angle, requires, anti_repeat_group, snowball_hooks, sort_order) VALUES
(0, 'You lived in {place}. Think about a first-time visitor, someone you cared about seeing it fresh. What would you show them that the guidebooks miss? Maybe a backyard, a diner, or a view only locals know about.', 'place', '{place}', 'hometown', 'place', '{has_places}', 'hometown_intro', '{hometown,neighborhood}', 51),
(0, 'Close your eyes and think about what {place} actually smelled like. Not the postcard version, the real one. Maybe it was the air after rain, a bakery on a certain block, or the way the seasons changed. What hits you first?', 'place', '{place}', 'sensory', 'feeling', '{has_places}', 'place_smell', '{sensory,hometown}', 52),
(0, 'Think about someone from {place} you lost touch with but still wonder about. Maybe it was a neighbor, a classmate, or someone you saw around all the time. What do you remember about them, and what would you ask if you ran into them tomorrow?', 'place', '{place}', 'connections', 'people', '{has_places}', 'place_person_lost', '{friendship,hometown}', 53),
(0, 'There''s probably a spot in {place} that doesn''t exist anymore, or has changed so much it''s unrecognizable. Maybe a store, a hangout, or a corner that felt important. Picture it the way it was. What would someone miss who never got to see it?', 'place', '{place}', 'nostalgia', 'place', '{has_places}', 'vanished_spot', '{nostalgia,change}', 54),
(0, 'Think about your favorite time of day in {place}. Maybe it was early morning before anyone was up, the golden hour before dinner, or late at night when the streets went quiet. What made that hour yours, and what were you usually doing?', 'place', '{place}', 'routine', 'feeling', '{has_places}', 'place_time_of_day', '{routine,peace}', 55),
(0, 'Every place has secrets only residents know. Think about {place} and something you understood about it that outsiders would never pick up on. Maybe it was a shortcut, an unspoken rule, or a thing everyone just knew. What comes to mind?', 'place', '{place}', 'insider', 'place', '{has_places}', 'place_insider', '{local,secrets}', 56),
(0, 'Weather can define a place as much as anything else. Think about {place} and a kind of weather that sticks in your memory. Maybe a snowstorm that shut everything down, a summer that wouldn''t end, or the way the wind felt at a certain time of year.', 'place', '{place}', 'sensory', 'feeling', '{has_places}', 'place_weather', '{weather,sensory,seasons}', 57),
(0, 'When you needed to be alone in {place}, where did you go? Maybe it was a park bench, a room in your house, or a spot no one else thought of as special. Think about that place, what it looked like, and what you were usually working through when you went there.', 'place', '{place}', 'solitude', 'place', '{has_places}', 'place_alone_spot', '{solitude,retreat}', 58),
(0, 'Think about a food that was specific to {place}, something you couldn''t easily find anywhere else. Maybe it was a dish at a local restaurant, a recipe that belonged to the area, or something a neighbor made. What was it, and who did you eat it with?', 'place', '{place}', 'food', 'object', '{has_places}', 'place_food', '{food,hometown,nostalgia}', 59),
(0, 'There are sounds that belong to specific places. Think about a sound you associate with {place} that you don''t hear in your life anymore. Maybe it was a church bell, a train, a neighbor''s dog, or the hum of a particular street. What was it?', 'place', '{place}', 'sensory', 'feeling', '{has_places}', 'place_sound', '{sensory,nostalgia,loss}', 60),
(0, 'If you went back to {place} tomorrow, what''s the first thing you''d do? Maybe you''d drive a certain route, visit a person, eat somewhere specific, or just stand in a spot and take it in. Walk me through what that first hour would look like.', 'place', '{place}', 'return', 'event', '{has_places}', 'place_return', '{return,nostalgia}', 61),
(0, 'Think about what home felt like in {place}. Not the building itself, but the feeling of being inside it. Maybe it was warm and noisy, or quiet and still, or something that shifted depending on who was there. What was the atmosphere?', 'place', '{place}', 'belonging', 'feeling', '{has_places}', 'place_home_feeling', '{belonging,comfort}', 62),
(0, 'Think about a neighbor from {place} who stands out in your memory. Maybe they were kind, maybe they were a character, maybe they kept to themselves in an interesting way. What do you remember about them, and what role did they play in the texture of your life there?', 'place', '{place}', 'community', 'people', '{has_places}', 'place_neighbor', '{community,characters}', 63),
(0, 'Every place has traditions that feel normal until you leave and realize nobody else does them. Think about {place} and a holiday, custom, or ritual that belonged to life there. What was it, and do you still carry any part of it with you?', 'place', '{place}', 'traditions', 'event', '{has_places}', 'place_tradition', '{traditions,culture}', 64),
(0, 'Living somewhere changes you in ways you don''t always notice while it''s happening. Think about what {place} taught you about yourself. Maybe it was patience, independence, a way of seeing the world, or something you couldn''t have learned anywhere else.', 'place', '{place}', 'growth', 'turning_point', '{has_places}', 'place_lesson', '{growth,identity}', 65),
(0, 'How did you end up in {place} in the first place? Maybe your family moved, you followed an opportunity, or it just sort of happened. Think about the story of your arrival. What were you expecting, and how did the reality compare?', 'place', '{place}', 'origins', 'event', '{has_places}', 'place_origin_story', '{origins,decisions}', 66),
INSERT INTO prompt_seed_library (tier, text, anchor, placeholders, category, angle, requires, anti_repeat_group, snowball_hooks, sort_order) VALUES
(1, 'Think about {hometown} during the holidays when you were a kid. Maybe it was the decorations on the street, the way people gathered, or a tradition your family kept. What did the season feel like there, and what do you miss about it?', 'place', '{hometown}', 'holidays', 'place', '{has_places}', 'holiday_hometown', '{holidays,childhood,traditions}', 131),
(1, 'You and {person_name} probably have a tradition or ritual that no one else would fully understand. Maybe it started by accident or became routine over time. What is it, and what would it mean if it stopped?', 'person', '{person_name}', 'traditions', 'people', '{has_contacts}', 'person_tradition_unique', '{traditions,bonding}', 132),
(1, 'Think about the most beautiful thing you''ve ever seen in person, not in a photo. Maybe it was a landscape, a face, a storm, or something handmade. What made it stop you in your tracks, and where were you when it happened?', NULL, '{}', 'beauty', 'feeling', '{answered_3+}', 'most_beautiful', '{beauty,awe}', 133),
(1, 'Think about a job you had early on that taught you something you didn''t expect. Maybe it was about people, about yourself, or about how the world works. What was the job, what happened there, and what stuck with you?', NULL, '{}', 'work', 'event', '{answered_3+}', 'early_job', '{work,growth,lessons}', 134),
(1, 'Most families have a recipe that carries more weight than the ingredients suggest. Maybe it came from a grandmother, was only made on special occasions, or tastes like a whole chapter of your life. What''s yours, and what story does it hold?', NULL, '{}', 'food', 'object', '{answered_3+}', 'family_recipe', '{food,family,heritage}', 135),
(1, 'Think about the bravest thing you ever saw {person_name} do. Maybe it was a big moment or something quiet that nobody else noticed. What did they do, what were the stakes, and what did it show you about who they are?', 'person', '{person_name}', 'courage', 'people', '{has_contacts}', 'person_brave', '{courage,admiration}', 136),
(1, 'Think about a game, sport, or activity you played growing up that kids today have probably never heard of. Maybe it required a whole neighborhood, some improvised equipment, or rules you made up. What was it, and what was it like to play?', NULL, '{}', 'childhood', 'event', '{answered_3+}', 'childhood_game', '{childhood,play,nostalgia}', 137),
(1, 'Think about the first concert, show, or live performance you ever attended. Maybe it was overwhelming, magical, or not what you expected. Who took you, where was it, and what do you remember most about being in that crowd?', NULL, '{}', 'culture', 'event', '{answered_3+}', 'first_performance', '{culture,firsts}', 138),
(1, 'Nicknames carry stories. Think about one you had that you either loved or hated. Who gave it to you, why did it stick, and what would it tell someone about who you were at the time?', NULL, '{}', 'identity', 'feeling', '{answered_3+}', 'nickname', '{identity,humor}', 139),
(1, 'Think about a lesson {person_name} taught you the hard way. Maybe it was something they said directly, a boundary they set, or a situation that forced the lesson into the open. What was it, and how did you feel at the time compared to how you feel about it now?', 'person', '{person_name}', 'lessons', 'people', '{has_contacts}', 'person_hard_lesson', '{lessons,growth}', 140),
(1, 'Picture your family''s dinner table. Think about who sat where, what the mood was like, and what usually happened during a meal. Was it loud, quiet, formal, chaotic? What''s the thing you remember most about those gatherings?', NULL, '{}', 'family', 'place', '{answered_3+}', 'dinner_table', '{family,home,routine}', 141),
(1, 'Most families have a holiday story they still bring up. Maybe something went wrong, someone did something hilarious, or an unexpected guest changed everything. Think about yours. What happened, and who tells it best?', NULL, '{}', 'holidays', 'event', '{answered_3+}', 'holiday_memory', '{holidays,family,stories}', 142),
(1, 'Think about what you wanted to be when you grew up. Maybe you had a clear picture, or maybe it changed every week. When did the childhood dream start shifting into something more real, and what replaced it?', NULL, '{}', 'dreams', 'turning_point', '{answered_3+}', 'childhood_dream', '{dreams,growing_up}', 143),
(1, 'Road trips and long car rides have a way of burning into memory. Think about one you remember in detail. Maybe it was the conversation, the scenery, the music playing, or something that happened along the way. What stands out?', NULL, '{}', 'travel', 'event', '{answered_3+}', 'road_trip', '{travel,adventure}', 144),
(1, 'Think about the view from your childhood bedroom window. Maybe you stared at it while daydreaming, watched the seasons change through it, or used it as an escape. What did you see, and what was going through your mind when you looked out?', NULL, '{}', 'childhood', 'place', '{answered_3+}', 'bedroom_view', '{childhood,home,sensory}', 145),
(1, 'There are seasons of life that leave you with mixed feelings when you look back. Maybe it was exciting but exhausting, or painful but full of growth. Think about one of those chapters. What was going on, and how do you hold it now?', NULL, '{}', 'reflection', 'feeling', '{answered_3+}', 'complicated_season', '{reflection,ambivalence}', 146),
(1, 'Think about a time {person_name} made you feel truly seen. Not flattered or complimented, but understood in a way that went deeper. Maybe it was something they said, noticed, or did without being asked. What was the moment?', 'person', '{person_name}', 'connection', 'people', '{has_contacts}', 'person_seen', '{connection,intimacy}', 147),
(1, 'Think about the longest you''ve gone without seeing someone you love, and what the reunion was like. Maybe you ran to each other, or maybe it was quiet and strange at first. What had changed in the time apart, and what felt exactly the same?', NULL, '{}', 'separation', 'event', '{answered_3+}', 'long_separation', '{separation,reunion,love}', 148),
(1, 'Saturday mornings can define a whole era of childhood. Think about what yours looked like. Maybe it was cartoons, chores, a parent''s routine, or freedom to roam. What did that morning feel like, and who else was up?', NULL, '{}', 'childhood', 'event', '{answered_3+}', 'saturday_morning', '{childhood,routine,comfort}', 149),
(1, 'There''s probably a piece of music that can bring you to tears no matter when you hear it. Maybe it''s tied to a person, a memory, or a feeling you can''t quite name. Think about what the song is, and what it unlocks in you every time.', NULL, '{}', 'music', 'feeling', '{answered_3+}', 'crying_music', '{music,emotion}', 150),
(1, 'Think about the first big purchase you ever made. Maybe it was a car, an instrument, or something you''d been eyeing for months. What was it, how long did you save, and what did it feel like to finally have it in your hands?', NULL, '{}', 'milestones', 'event', '{answered_3+}', 'first_purchase', '{milestones,independence}', 151),
(1, 'Every family has unspoken rules or quirks that feel normal until you realize nobody else does them. Think about one from yours. Maybe it was a mealtime ritual, a holiday tradition, or a way of handling conflict. What was it?', NULL, '{}', 'family', 'event', '{answered_3+}', 'family_rule', '{family,quirks}', 152),
(1, 'Some compliments land so deep they stay with you for years. Think about one someone gave you that you still carry. Who said it, what were the circumstances, and why did it matter so much? Maybe it was the timing, or maybe they named something you were afraid to claim.', NULL, '{}', 'validation', 'feeling', '{answered_3+}', 'lasting_compliment', '{validation,self_worth}', 153),
(1, 'Think about a pet that was really more than a pet. Maybe they were your companion during a hard time, your constant for years, or the creature who understood your mood better than most people. What was their name, and what did they mean to you?', NULL, '{}', 'animals', 'people', '{answered_3+}', 'beloved_pet', '{animals,love,loss}', 154),
(1, 'Families pass down more than recipes and heirlooms. Think about a superstition, habit, or saying you picked up from someone in your family. Maybe you knock on wood, avoid certain things, or catch yourself repeating a phrase. Where did it come from?', NULL, '{}', 'family', 'object', '{answered_3+}', 'family_superstition', '{family,habits,heritage}', 155),
(1, 'Some summers stand out from all the rest. Think about one that defined a period of your life. Maybe it was the people, the freedom, a trip, or just the feeling of those months. What happened that summer, and why does it still feel different from the others?', NULL, '{}', 'seasons', 'event', '{answered_3+}', 'standout_summer', '{seasons,nostalgia}', 156),
(1, 'Think about the first movie you remember seeing in a theater. Maybe it was the darkness, the size of the screen, or the way the story hit you. Who took you, what was the movie, and what do you remember about walking out afterward?', NULL, '{}', 'culture', 'event', '{answered_3+}', 'first_movie', '{culture,firsts,childhood}', 157),
(1, 'Think about a promise you made to yourself that you actually kept. Maybe it was about changing something, sticking with something, or never going back to something. What was the promise, when did you make it, and what did keeping it cost you?', NULL, '{}', 'integrity', 'turning_point', '{answered_3+}', 'kept_promise', '{integrity,determination}', 158),
(1, 'Some of the most valuable skills come from watching someone else, not from a class. Think about something you learned just by paying attention to another person. Maybe it was how they fixed things, handled a situation, or moved through the world. What did you pick up?', NULL, '{}', 'learning', 'event', '{answered_3+}', 'observed_skill', '{learning,mentors}', 159),
(1, 'Think about the longest walk you ever took. Maybe it was intentional, or maybe you just needed to move. Where did you go, what were you working through, and did anything shift by the time you stopped?', NULL, '{}', 'contemplation', 'event', '{answered_3+}', 'longest_walk', '{contemplation,movement}', 160),
(1, 'There''s probably a conversation from your past you wish you could have recorded. Maybe for the wisdom in it, the humor, or just the sound of someone''s voice. Who were you talking to, and what was said that you don''t want to forget?', NULL, '{}', 'moments', 'event', '{answered_3+}', 'wish_recorded', '{moments,wisdom}', 161),
(1, 'Think about your first car, or the first vehicle that gave you real freedom. Maybe it was beautiful, maybe it was barely running, but it took you places. What did it look like, where did you go in it, and what does it represent about that time in your life?', NULL, '{}', 'milestones', 'object', '{answered_3+}', 'first_car', '{milestones,freedom,adventure}', 162),
(1, 'Think about what you and your best friend used to do after school. Maybe you went to the same spot every day, had a routine, or just made things up as you went. What was the world like in those hours between school and dinner?', NULL, '{}', 'friendship', 'event', '{answered_3+}', 'after_school', '{friendship,childhood}', 163),
(1, 'Think about a time you pretended to be fine when you weren''t. Maybe you held it together at work, smiled through a gathering, or carried something alone. Did anyone notice? What would it have meant if someone had?', NULL, '{}', 'vulnerability', 'feeling', '{answered_3+}', 'pretending_fine', '{vulnerability,perception}', 164),
(1, 'Think about a project or creation you poured yourself into. Maybe it was something you built, wrote, organized, or made from scratch. What drove you, how long did it take, and what did it feel like when it was finished or when you had to let it go?', NULL, '{}', 'creation', 'event', '{answered_3+}', 'passion_project', '{creation,pride,dedication}', 165),
(1, 'There''s probably a morning routine from an earlier time in your life that you miss. Maybe it was the slowness, the people involved, or the feeling of a day stretching ahead. What was the routine, and what made that version of morning feel so good?', NULL, '{}', 'routine', 'event', '{answered_3+}', 'missed_routine', '{routine,nostalgia}', 166),
(1, 'Think about the first time you held someone tiny and new, whether it was your child, a niece, a nephew, or a friend''s baby. Where were you, what did you feel, and did it change something in you? Maybe it was awe, tenderness, or something you couldn''t name.', NULL, '{}', 'family', 'feeling', '{answered_3+}', 'holding_baby', '{family,tenderness,awe}', 167),
(1, 'Think about a gift you gave that you were especially proud of. Maybe you made it, searched for it, or just knew it was perfect the moment you found it. What was it, who was it for, and what was their reaction?', NULL, '{}', 'generosity', 'object', '{answered_3+}', 'proud_gift', '{generosity,thoughtfulness}', 168),
(1, 'Think about a teacher or coach who changed something in you. Maybe they pushed you, believed in you, or said something you still hear in your head. Who were they, what did they do, and how did their influence ripple through your life?', NULL, '{}', 'mentors', 'people', '{answered_3+}', 'teacher_impact', '{mentors,education}', 169),
(1, 'Think about the scariest thing that ever happened to you that you can laugh about now. Maybe time softened it, or the retelling turned it into comedy. What happened, how terrified were you, and when did it become a good story?', NULL, '{}', 'resilience', 'event', '{answered_3+}', 'scary_now_funny', '{resilience,humor,time}', 170),
(1, 'Some short trips create outsized memories. Think about a weekend getaway or quick trip that left a bigger mark than you expected. Where did you go, who was with you, and what happened that elevated it beyond a simple outing?', NULL, '{}', 'travel', 'event', '{answered_3+}', 'weekend_trip', '{travel,surprise}', 171),
(1, 'Think about a TV show or movie your whole family would watch together. Maybe it was a weekly ritual, a holiday tradition, or just the one thing everyone could agree on. What was it, where did you watch, and what was the atmosphere like?', NULL, '{}', 'family', 'object', '{answered_3+}', 'family_show', '{family,culture,togetherness}', 172),
(1, 'Think about the most memorable meal someone cooked for you. Maybe it was your mother''s cooking, a friend who went all out, or someone making a simple thing with love. What was the food, who made it, and what was going on in your life at the time?', NULL, '{}', 'food', 'feeling', '{answered_3+}', 'cooked_meal', '{food,love,care}', 173),
(1, 'First days carry a specific kind of energy. Think about your first day at a new school or a new job. What did you wear, who was the first person who talked to you, and what was going through your mind? Was the version of yourself you presented that day the real one?', NULL, '{}', 'transitions', 'event', '{answered_3+}', 'first_day', '{transitions,anxiety,beginnings}', 174),
(1, 'Think about something you did as a teenager that still makes you cringe, in a fond way. Maybe it was a fashion choice, something you said to a crush, or a stunt that seemed brilliant at the time. What happened, and what does it tell you about who you were then?', NULL, '{}', 'youth', 'event', '{answered_3+}', 'teen_cringe', '{youth,humor,growth}', 175),
(1, 'Some phone calls change everything. Think about one you''ll never forget. Maybe it was good news, bad news, or a voice you didn''t expect to hear. Where were you when it came, what was said, and what happened in the hours after you hung up?', NULL, '{}', 'moments', 'event', '{answered_3+}', 'memorable_call', '{moments,surprise}', 176),
(1, 'There are books that find you at exactly the right moment. Think about one that showed up when you needed it most. Maybe someone recommended it, you stumbled on it, or it had been on your shelf for years. What was it, and what did it give you?', NULL, '{}', 'culture', 'object', '{answered_3+}', 'right_time_book', '{culture,timing}', 177),
(1, 'Think about a time you felt completely out of your element. Maybe you were in a new country, a new social circle, or a situation you had no training for. How did you handle it, and did something unexpected come from being that uncomfortable?', NULL, '{}', 'discomfort', 'event', '{answered_3+}', 'out_of_element', '{discomfort,growth}', 178),
(1, 'Think about the most thoughtful thing anyone has ever done for you. Maybe it took planning, or maybe it was a spontaneous act that showed they really understood what you needed. What was it, who did it, and what did it tell you about how they see you?', NULL, '{}', 'gratitude', 'feeling', '{answered_3+}', 'most_thoughtful', '{gratitude,love}', 179),
(1, 'There''s usually a chore or task from your past that you actually enjoyed. Maybe it was mowing the lawn, folding laundry, or washing dishes. Something about the rhythm or the solitude made it meditative. What was it, and what made it feel good?', NULL, '{}', 'routine', 'feeling', '{answered_3+}', 'enjoyable_chore', '{routine,meditation}', 180),
(1, 'Think about a view from a window you''ll never forget. Maybe it was a hospital room, a hotel, a train, or your first apartment. What did you see, and what was happening in your life at the time? Sometimes a view carries a whole era.', NULL, '{}', 'sensory', 'place', '{answered_3+}', 'window_view', '{sensory,beauty}', 181),
(1, 'Think about a lie you told as a kid that you still remember. Maybe you got caught, or maybe you got away with it and the guilt stuck around. What was the lie, why did you tell it, and what did it teach you about honesty?', NULL, '{}', 'childhood', 'event', '{answered_3+}', 'childhood_lie', '{childhood,innocence,humor}', 182),
(1, 'Think about the person you''d want in the room if everything went sideways. Not for their skills, but for their presence. Maybe they''re calm, steady, or just someone who makes you feel like things will be okay. Who is it, and what is it about them?', NULL, '{}', 'trust', 'people', '{answered_3+}', 'trust_person', '{trust,reliability}', 183),
(1, 'Think about a dance, a hug, or a moment of physical closeness that you remember vividly. Maybe it was a slow dance, a goodbye embrace, or someone holding your hand at the right moment. What was the context, and what did it feel like in your body?', NULL, '{}', 'physical', 'feeling', '{answered_3+}', 'vivid_contact', '{physical,emotion}', 184),
(1, 'Think about a difficult time you weathered alongside someone else. Maybe it was a literal storm, a family crisis, or a long stretch of uncertainty. Who was with you, how did you lean on each other, and what did that shared struggle create between you?', NULL, '{}', 'resilience', 'event', '{answered_3+}', 'storm_together', '{resilience,bonding}', 185),
(1, 'Think about the best party or gathering you ever attended. Maybe it was the people, the energy, the music, or something unexpected that happened. Where was it, what made it special, and is there a moment from it you can still feel?', NULL, '{}', 'celebration', 'event', '{answered_3+}', 'best_party', '{celebration,joy}', 186),
(1, 'Think about a bedtime routine from your childhood that you can almost still feel. Maybe it was a story someone read, a song, a prayer, or just the way your blankets were tucked. What was the routine, and what did it give you that you still carry?', NULL, '{}', 'childhood', 'feeling', '{answered_3+}', 'bedtime_routine', '{childhood,comfort,safety}', 187),
(1, 'Think about a photograph of yourself that captures who you really were at that moment. Not posed, not flattering necessarily, but true. What''s happening in the picture, how old are you, and what does it say about you that words might miss?', NULL, '{}', 'identity', 'object', '{answered_3+}', 'capturing_photo', '{identity,truth}', 188),
(1, 'Think about the kindest thing you''ve ever done that no one knows about. Maybe you helped someone quietly, made a sacrifice behind the scenes, or showed up in a way that was never acknowledged. What was it, and why did you keep it to yourself?', NULL, '{}', 'kindness', 'event', '{answered_3+}', 'secret_kindness', '{kindness,character}', 189),
(1, 'Think about a room you spent a lot of time in that you can still walk through in your mind. Maybe it''s a childhood bedroom, a kitchen, or a workshop. Picture the furniture, the light, the sounds. What were you usually doing in that room, and who else was there?', NULL, '{}', 'nostalgia', 'place', '{answered_3+}', 'mental_room', '{nostalgia,detail}', 190),
(1, 'Think about the first thing you ever saved up your own money to buy. Maybe it took weeks or months, and you had a specific plan. What was it, how did you earn the money, and what did it feel like when you finally had it?', NULL, '{}', 'milestones', 'object', '{answered_3+}', 'saved_up', '{milestones,patience}', 191),
(1, 'Ceremonies can lodge in your memory in unexpected ways. Think about a wedding, a funeral, or a gathering that you''ll always remember. Maybe it was the beauty of it, the grief, or a moment when everyone''s guard came down. What happened?', NULL, '{}', 'ceremony', 'event', '{answered_3+}', 'memorable_ceremony', '{ceremony,emotions}', 192),
(1, 'Cars have a way of loosening conversations. Think about the best talk you ever had while driving or riding with someone. What were you talking about, where were you going, and was there something about the car that made the conversation easier?', NULL, '{}', 'connection', 'event', '{answered_3+}', 'car_conversation', '{connection,intimacy}', 193),
(1, 'Scars tell stories. Think about one of yours, physical or otherwise, and the story behind it. How did you get it, how old were you, and has the way you think about it changed over the years?', NULL, '{}', 'stories', 'object', '{answered_3+}', 'scar_story', '{stories,resilience}', 194),
(1, 'Think about a restaurant or eatery you used to go to that''s closed now. Maybe you had a usual order, a favorite seat, or a person behind the counter who knew your name. What was it, what did you always get, and what do you miss about it?', NULL, '{}', 'food', 'place', '{answered_3+}', 'closed_restaurant', '{food,nostalgia,loss}', 195),
(1, 'Some friendships start in the most unlikely ways. Think about a friend who entered your life through strange circumstances, a coincidence, a misunderstanding, or a situation where you least expected to find someone. How did it happen?', NULL, '{}', 'friendship', 'people', '{answered_3+}', 'unexpected_friend', '{friendship,serendipity}', 196),
(1, 'Houses make sounds that become invisible until they''re gone. Think about a sound your house used to make that you didn''t know you''d miss. Maybe it was floorboards, a furnace, a clock, or the way a door closed. What was it, and where does hearing it in your memory put you?', NULL, '{}', 'sensory', 'feeling', '{answered_3+}', 'house_sound', '{sensory,home,nostalgia}', 197),
(1, 'Think about a time you were wrong about someone in a good way. Maybe you judged them too quickly, underestimated them, or assumed the worst. What changed your mind, and what did it teach you about the stories you tell yourself about people?', NULL, '{}', 'perception', 'people', '{answered_3+}', 'wrong_about_someone', '{perception,surprise}', 198),
(1, 'Think about a secret spot you had as a kid, a place that was all yours. Maybe it was under a tree, in a closet, behind a building, or up on a roof. What did it look like, what did you do there, and who, if anyone, knew about it?', NULL, '{}', 'childhood', 'place', '{answered_3+}', 'secret_spot', '{childhood,solitude,imagination}', 199),
(1, 'Think about your grandparents'' house and what it smelled like. Maybe it was cooking, old furniture, a garden, or something you can''t quite name. Let that smell pull you back. Where are you standing, and what else do you notice?', NULL, '{}', 'family', 'feeling', '{answered_3+}', 'grandparent_smell', '{family,sensory,nostalgia}', 200),
(1, 'Think about a piece of clothing from your past that you wish you still had. Maybe it was a jacket that fit perfectly, a shirt from a meaningful trip, or something that belonged to someone you love. What was it, and what story would it tell?', NULL, '{}', 'fashion', 'object', '{answered_3+}', 'lost_clothing', '{fashion,nostalgia}', 201),
(1, 'Think about a time the weather perfectly matched how you were feeling. Maybe it was rain during a sad day, sunshine during a celebration, or a storm that echoed something churning inside you. What was happening, and did the weather make it more intense?', NULL, '{}', 'atmosphere', 'feeling', '{answered_3+}', 'weather_matched', '{atmosphere,pathetic_fallacy}', 202),
(1, 'Think about a handwritten note or letter that you''ve kept somewhere. Maybe it''s in a drawer, tucked in a book, or folded in your wallet. Who wrote it, what does it say, and why has it traveled with you this long?', NULL, '{}', 'keepsakes', 'object', '{answered_3+}', 'saved_letter', '{keepsakes,communication}', 203),
(1, 'Think about a meal you ate alone that turned out to be something you needed. Maybe the solitude was a relief, or maybe you were in a new place and the food grounded you. Where were you, what did you eat, and what was going on in your head?', NULL, '{}', 'solitude', 'event', '{answered_3+}', 'solo_meal', '{solitude,self_care}', 204),
(1, 'Think about a time you rehearsed exactly what you were going to say, but when the moment came, something completely different came out of your mouth. Maybe it was better, maybe it was worse. What happened, and why did the script fall apart?', NULL, '{}', 'honesty', 'event', '{answered_3+}', 'unrehearsed', '{honesty,spontaneity}', 205),
(1, 'Think about a New Year''s Eve you actually remember, not for the party, but for how you felt. Maybe you were hopeful, lonely, surrounded by people, or standing somewhere quiet. Where were you, who was near you, and what were you carrying into the new year?', NULL, '{}', 'holidays', 'feeling', '{answered_3+}', 'new_years_feeling', '{holidays,reflection}', 206),
(1, 'Think about a kitchen smell that you could recognize anywhere, whether from your own kitchen or someone else''s. Maybe it''s a specific spice, bread baking, or coffee at a certain hour. What is it, whose kitchen does it belong to, and what was happening when that smell was in the air?', NULL, '{}', 'sensory', 'feeling', '{answered_3+}', 'kitchen_smell', '{sensory,food,home}', 207),
(1, 'Look around the room you''re in right now. Think about the most important thing in it, and not necessarily the most expensive. Maybe it''s a photo, a chair, a plant, or something on a shelf. Why does it matter, and what''s the story behind it being there?', NULL, '{}', 'present', 'object', '{answered_3+}', 'room_object', '{present,meaning}', 208),
(1, 'Families often tell stories about you from before you can remember. Think about one of those stories. Who tells it, what supposedly happened, and does it match the person you think you are? Is there a detail you suspect has been embellished?', NULL, '{}', 'family', 'event', '{answered_3+}', 'family_story', '{family,identity}', 209),
(1, 'Think about your first real job, not babysitting or odd work, but the first time you felt like you were in the adult world. What were the people like, what did the space look like, and what did you learn about yourself in those early days?', NULL, '{}', 'work', 'event', '{answered_3+}', 'first_real_job', '{work,coming_of_age}', 210),
(1, 'There''s usually a song that belongs to a specific drive or journey. Maybe it came on the radio at the perfect moment, or you played it on repeat during a long trip. What was the song, where were you going, and what was on your mind?', NULL, '{}', 'music', 'feeling', '{answered_3+}', 'journey_song', '{music,travel}', 211),
(1, 'Think about a small thing someone does for you regularly that you never take for granted. Maybe it''s how they make your coffee, a text they send, or a quiet act of care they probably don''t think about. What is it, and why does it mean so much?', NULL, '{}', 'gratitude', 'feeling', '{answered_3+}', 'daily_gratitude', '{gratitude,love,routine}', 212),
(1, 'Think about the closest thing to a miracle you''ve ever experienced. Maybe it was a near miss, a coincidence that defied logic, or something that worked out when all signs said it wouldn''t. What happened, and how do you explain it to yourself?', NULL, '{}', 'wonder', 'event', '{answered_3+}', 'near_miracle', '{wonder,luck}', 213),
(1, 'Think about a thing you do exactly the way one of your parents did it. Maybe it''s how you fold towels, discipline a child, handle conflict, or stir a pot. When did you first notice the echo, and how does it make you feel?', NULL, '{}', 'heritage', 'event', '{answered_3+}', 'parent_echo', '{heritage,patterns}', 214),
(1, 'Think about a rainy day from your past that was actually perfect. Maybe you stayed in, got caught in it, or watched it from a window with someone. What made the rain feel like a gift instead of an inconvenience? Who was there?', NULL, '{}', 'weather', 'event', '{answered_3+}', 'perfect_rain', '{weather,comfort}', 215),
(1, 'Think about the most alive you''ve ever felt. Not the happiest necessarily, but the most awake, the most present. Maybe you were moving, creating, talking, or just standing somewhere. What was the moment, and what made every cell in your body hum?', NULL, '{}', 'vitality', 'feeling', '{answered_3+}', 'most_alive', '{vitality,peak_experience}', 216),
(1, 'Think about a toy or game from childhood that you could still describe in perfect detail, the color, the weight, the way it felt in your hands. What was it, how did you play with it, and who did you play with?', NULL, '{}', 'childhood', 'object', '{answered_3+}', 'childhood_toy', '{childhood,detail,play}', 217),
(1, 'Sunday afternoons can have a very specific texture. Think about one that defined a chapter of your life. Maybe it was visiting someone, doing a hobby, cooking, or watching something. What did your Sundays look like, and what does that tell you about who you were then?', NULL, '{}', 'routine', 'event', '{answered_3+}', 'sunday_activity', '{routine,chapters}', 218),
(1, 'Think about the most important thing your best friend doesn''t know about you. Maybe you''ve kept it private for a reason, or maybe it just never came up. What is it, and what do you think they''d say if they knew?', NULL, '{}', 'secrets', 'feeling', '{answered_3+}', 'friend_doesnt_know', '{secrets,vulnerability}', 219),
(1, 'Think about a time you showed up for someone in a way that cost you something. Maybe it was time, money, sleep, or emotional energy. What was the situation, what did you give, and would you do it again?', NULL, '{}', 'sacrifice', 'event', '{answered_3+}', 'showed_up', '{sacrifice,loyalty}', 220),
(1, 'Think about a sunset, a sunrise, or a sky that you can still picture clearly. Maybe you were on a trip, sitting on a porch, or stopped on the side of the road. What did it look like, and what was going through your life at the time?', NULL, '{}', 'nature', 'place', '{answered_3+}', 'memorable_sky', '{nature,beauty}', 221),
(1, 'Think about the weirdest thing you''ve ever collected. Maybe it was intentional, maybe it accumulated without you noticing. What was it, how did it start, and what did it say about you that you might not have admitted at the time?', NULL, '{}', 'quirks', 'object', '{answered_3+}', 'weird_collection', '{quirks,personality}', 222),
(1, 'Think about a time silence said more than any words could have. Maybe you were sitting with someone, standing in a doorway, or driving home. What was the silence about, and what passed between you and the other person without being spoken?', NULL, '{}', 'communication', 'feeling', '{answered_3+}', 'meaningful_silence', '{communication,depth}', 223),
(1, 'Think about a trip that was supposed to be purely fun but turned into something more meaningful. Maybe a conversation happened, a realization hit, or you saw something that shifted your perspective. Where did you go, and what changed?', NULL, '{}', 'travel', 'event', '{answered_3+}', 'meaningful_trip', '{travel,depth}', 224),
(1, 'There''s probably a sound that still means home to you. Maybe it''s a specific door closing, a voice calling from another room, or the hum of a kitchen. What is the sound, and what version of home does it take you to?', NULL, '{}', 'sensory', 'feeling', '{answered_3+}', 'home_sound', '{sensory,home,belonging}', 225),
(1, 'Think about a birthday you remember not for the cake or the presents but for something else entirely. Maybe it was an unexpected visitor, a feeling that surprised you, or a conversation that happened that day. What made it different?', NULL, '{}', 'birthdays', 'event', '{answered_3+}', 'off_script_birthday', '{birthdays,surprise}', 226),
(1, 'Think about a piece of advice you gave someone that you probably should have taken yourself. Maybe you said it with full conviction and then realized you hadn''t lived it. What was the advice, and why is it easier to give than to follow?', NULL, '{}', 'wisdom', 'feeling', '{answered_3+}', 'own_advice', '{wisdom,irony}', 227),
(1, 'Think about a craft, recipe, or technique that was passed down to you from someone in your family. Maybe you learned by watching, or maybe they sat you down and taught you. Who was the teacher, what was the skill, and do you still practice it?', NULL, '{}', 'heritage', 'object', '{answered_3+}', 'passed_down', '{heritage,family,skills}', 228),
(1, 'Think about the best season in the place where you grew up and what the air smelled like during that time. Maybe it was the warmth of summer grass, the sharpness of fall, or something blooming in spring. Close your eyes and breathe it in. What comes back?', NULL, '{}', 'sensory', 'feeling', '{answered_3+}', 'season_smell', '{sensory,seasons,childhood}', 229),
(1, 'Think about a dream, a real sleeping dream, that you still remember years later. Maybe it was vivid, unsettling, beautiful, or just strange. What happened in it, and why do you think your mind made that particular story? Does it connect to something in your waking life?', NULL, '{}', 'subconscious', 'feeling', '{answered_3+}', 'remembered_dream', '{subconscious,mystery}', 230);
INSERT INTO prompt_seed_library (tier, text, anchor, placeholders, category, angle, requires, anti_repeat_group, snowball_hooks, sort_order) VALUES
(2, 'Think about a conversation with {person_name} that you replay in your head sometimes. Maybe it was comforting, confrontational, or just unexpectedly honest. What was said, where were you, and why do you think your mind keeps going back to it?', 'person', '{person_name}', 'connection', 'people', '{has_contacts,answered_5+}', 'replayed_convo', '{connection,significance}', 231),
(2, 'Think about a trip that changed how you see something, maybe about yourself, about the world, or about someone you traveled with. Where did you go, what shifted, and did you notice the change happening or only after you came home?', NULL, '{}', 'travel', 'event', '{answered_5+}', 'perspective_trip', '{travel,growth}', 232),
(2, 'Think about a fight you had with {person_name}, not the surface argument, but what was really underneath it. Maybe it was about feeling unheard, a fear neither of you could name, or a pattern that kept repeating. What was the deeper thing?', 'person', '{person_name}', 'conflict', 'people', '{has_contacts,answered_5+}', 'person_conflict', '{conflict,depth}', 233),
(2, 'Think about a place you associate completely with {person_name}. Maybe you went there together often, or something important happened there. What is the place, and can you go there now without thinking of them?', 'person', '{person_name}', 'places', 'place', '{has_contacts,answered_5+}', 'person_place', '{places,association}', 234),
(2, 'Think about a decision you made to protect someone, even though it was hard on you. Maybe you kept a secret, absorbed a blow, or made a sacrifice they may not even know about. What did you do, and what did it cost you?', NULL, '{}', 'protection', 'event', '{answered_5+}', 'protective_decision', '{protection,sacrifice}', 235),
(2, 'Think about the most honest conversation you''ve ever had. Maybe it happened late at night, during a crisis, or in a quiet moment when someone''s guard came down. Who was it with, what was said, and what changed afterward?', NULL, '{}', 'honesty', 'event', '{answered_5+}', 'honest_convo', '{honesty,vulnerability}', 236),
(2, 'Think about the last time you really looked at {person_name}, not a glance but a real moment of seeing them. What did their face look like? Maybe you noticed something new, or maybe you saw something you''d always known but never put into words.', 'person', '{person_name}', 'observation', 'people', '{has_contacts,answered_5+}', 'person_look', '{observation,attention}', 237),
(2, 'Think about a moment when you realized {person_name} needed you, even though they didn''t say it. Maybe it was something in their voice, a look on their face, or just a feeling you had. What did you pick up on, and what did you do?', 'person', '{person_name}', 'intuition', 'people', '{has_contacts,answered_5+}', 'person_needed', '{intuition,care}', 238),
(2, 'Think about a place you lived that you didn''t appreciate until you left. Maybe you took the people for granted, the beauty of it, or the way life moved there. What do you see now that you couldn''t see while you were in it?', NULL, '{}', 'gratitude', 'place', '{answered_5+}', 'underappreciated_place', '{gratitude,hindsight}', 239),
(2, 'Think about a secret language you share with someone close to you. Maybe it''s a look that means "let''s go," a phrase that cracks you both up, or a gesture that carries a whole conversation. What is it, how did it develop, and what does it mean that you have it?', NULL, '{}', 'intimacy', 'people', '{answered_5+}', 'secret_language', '{intimacy,connection}', 240),
(2, 'Think about a photograph you took that means more to you than it would to anyone else. Maybe the composition is nothing special, but you know the full story. What''s in the picture, what''s just outside the frame, and what was going on when you pressed the button?', NULL, '{}', 'photography', 'object', '{answered_5+}', 'personal_photo', '{photography,meaning}', 241),
(2, 'Think about a time you had to choose between two people, two paths, or two versions of your life. Maybe both options had something real to offer. How did you decide, what did you lose, and do you still wonder about the road you didn''t take?', NULL, '{}', 'choices', 'turning_point', '{answered_5+}', 'fork_in_road', '{choices,consequences}', 242),
(2, 'Think about a moment you shared with {person_name} that bonded you in a way nothing else could have. Maybe it was a crisis, a secret, a laugh you couldn''t stop, or a quiet moment that sealed something. What happened, and what did it create between you?', 'person', '{person_name}', 'bonding', 'event', '{has_contacts,answered_5+}', 'person_bond', '{bonding,depth}', 243),
(2, 'Think about a fear you''ve never told anyone about. Not a phobia, but something deeper. Maybe it''s about losing something, about being seen a certain way, or about a possibility you try not to think about. What is it, and why has it stayed private?', NULL, '{}', 'vulnerability', 'feeling', '{answered_5+}', 'secret_fear', '{vulnerability,trust}', 244),
(2, 'Think about a promise someone made to you that they actually kept, even when it was hard. Maybe it would have been easy to forget, or circumstances changed, but they followed through. Who was it, what was the promise, and what did their follow-through mean to you?', NULL, '{}', 'trust', 'people', '{answered_5+}', 'kept_promise_other', '{trust,loyalty}', 245),
(2, 'Think about the most uncomfortable silence you''ve ever sat through. Maybe it was after an argument, during a visit, or in a room full of people. What was the silence about, how long did it last, and what broke it?', NULL, '{}', 'tension', 'event', '{answered_5+}', 'uncomfortable_silence', '{tension,resolution}', 246),
(2, 'Think about something you know about {person_name} that they''d probably be surprised you noticed. Maybe it''s a small habit, a preference, or a tell that shows how they''re really feeling. What have you picked up, and why do you think you noticed?', 'person', '{person_name}', 'observation', 'people', '{has_contacts,answered_5+}', 'person_noticed', '{observation,attention}', 247),
(2, 'Think about a night you stayed up way too late and it was completely worth it. Maybe it was a conversation that wouldn''t end, a creative streak, or just being with someone when the hours melted away. What kept you up, and who were you with?', NULL, '{}', 'spontaneity', 'event', '{answered_5+}', 'late_night', '{spontaneity,energy}', 248),
(2, 'Think about a meal you cooked for someone that was really an act of love. Maybe you spent hours on it, made their favorite, or cooked through your own exhaustion. Who was it for, what did you make, and what were you trying to say with the food?', NULL, '{}', 'love', 'event', '{answered_5+}', 'love_meal', '{love,food,care}', 249),
(2, 'Think about something {person_name} does that drives you a little crazy, but you know you''d miss it if it were gone. Maybe it''s a habit, a phrase they overuse, or a way they handle things that isn''t your style. What is it, and why does it matter that you accept it?', 'person', '{person_name}', 'acceptance', 'people', '{has_contacts,answered_5+}', 'person_annoyance', '{acceptance,love}', 250),
(2, 'Think about a piece of your story that would surprise most people who know you. Maybe it''s a chapter you don''t talk about, a side of yourself you keep quiet, or a past that doesn''t match the present. What is it, and why do you keep it to yourself?', NULL, '{}', 'hidden', 'event', '{answered_5+}', 'surprising_story', '{hidden,identity}', 251),
(2, 'Think about a room in your current home that has evolved into something you didn''t plan. Maybe a guest room became a studio, or a corner became sacred. What happened, and what does the room''s transformation say about how your life has shifted?', NULL, '{}', 'home', 'place', '{answered_5+}', 'evolved_room', '{home,organic}', 252),
(2, 'Think about the longest letter, email, or text you ever wrote. Maybe you agonized over every word, or it poured out in one sitting. Who was it to, what were you trying to say, and did it land the way you hoped?', NULL, '{}', 'communication', 'event', '{answered_5+}', 'long_message', '{communication,urgency}', 253),
(2, 'Think about an argument you lost that you now realize you should have lost. Maybe the other person was right, or maybe losing it taught you something about yourself. What was the argument, and when did you come around?', NULL, '{}', 'humility', 'turning_point', '{answered_5+}', 'lost_argument', '{humility,growth}', 254),
(2, 'Think about a photo of {person_name} that captures exactly who they are. Not their best angle, but their truest self. What are they doing in the picture, what''s their expression, and what does someone who loves them see when they look at it?', 'person', '{person_name}', 'essence', 'people', '{has_contacts,answered_5+}', 'person_photo', '{essence,truth}', 255),
(2, 'Think about a tradition you started yourself, something you didn''t inherit but created. Maybe it''s a holiday ritual, a weekly habit, or something you do with your family that nobody did in yours growing up. How did it begin, and what does it mean?', NULL, '{}', 'creation', 'event', '{answered_5+}', 'new_tradition', '{creation,intention}', 256),
(2, 'Think about the hardest apology you ever had to give. Maybe you put it off, rehearsed it, or blurted it out imperfectly. What had you done, what did it cost you to say sorry, and how did the other person respond?', NULL, '{}', 'accountability', 'event', '{answered_5+}', 'hard_apology', '{accountability,growth}', 257),
(2, 'Think about a moment of unexpected beauty you stumbled into. Maybe it was light hitting something, a scene on the street, or a person doing something ordinary that looked extraordinary. What did you see, and why did it stop you?', NULL, '{}', 'beauty', 'feeling', '{answered_5+}', 'unexpected_beauty', '{beauty,surprise}', 258),
(2, 'Think about what {person_name} does when they think nobody''s watching. Maybe they sing, talk to themselves, or have a little ritual that''s completely unguarded. What have you seen, and what does it tell you about who they really are?', 'person', '{person_name}', 'observation', 'people', '{has_contacts,answered_5+}', 'person_unguarded', '{observation,authenticity}', 259),
(2, 'Think about a habit from your twenties that you either deliberately kept or deliberately broke. Maybe it served you then but not now, or maybe you recognized something in it that needed to change. What was the habit, and what was the turning point?', NULL, '{}', 'habits', 'event', '{answered_5+}', 'twenties_habit', '{habits,evolution}', 260),
(2, 'Think about a question you''ve been asked in life that you''re still figuring out the answer to. Maybe it came from a friend, a therapist, or a child. What was the question, and how has your answer shifted over the years?', NULL, '{}', 'existential', 'feeling', '{answered_5+}', 'open_question', '{existential,searching}', 261),
(2, 'Think about the best hand-me-down you ever received. Maybe it was clothing, a tool, a piece of furniture, or something less tangible. Who gave it to you, what was its history, and what did receiving it feel like?', NULL, '{}', 'heritage', 'object', '{answered_5+}', 'hand_me_down', '{heritage,connection}', 262),
(2, 'Think about a morning when you woke up and knew, somehow, that everything was about to change. Maybe it was a feeling in your body, a conversation waiting to happen, or just the weight of a day you''d been dreading. What was the day, and were you right?', NULL, '{}', 'premonition', 'turning_point', '{answered_5+}', 'premonition_morning', '{premonition,change}', 263),
(2, 'Think about what the word "home" really means to you right now. Not an address, but a feeling. Maybe it''s a person, a state of mind, or a quality of light in a certain room. What does home feel like, and has that definition changed over the years?', NULL, '{}', 'belonging', 'feeling', '{answered_5+}', 'home_feeling', '{belonging,identity}', 264),
(2, 'Think about the most {person_name} thing {person_name} has ever done. The moment that was so completely, undeniably them that nobody else could have pulled it off. What happened, and why was it so perfectly in character?', 'person', '{person_name}', 'character', 'people', '{has_contacts,answered_5+}', 'person_quintessential', '{character,identity}', 265),
(2, 'Think about a failure that taught you more than any success ever did. Maybe it was humbling, painful, or embarrassing, but looking back, it gave you something essential. What went wrong, and what did the wreckage teach you?', NULL, '{}', 'failure', 'event', '{answered_5+}', 'instructive_failure', '{failure,wisdom}', 266),
(2, 'Think about a time you witnessed something you weren''t supposed to see. Maybe it was tender, private, surprising, or unsettling. What did you see, and how did it change the way you think about the person or the situation?', NULL, '{}', 'witness', 'event', '{answered_5+}', 'unseen_witness', '{witness,secrets}', 267),
(2, 'Think about a compliment that made you uncomfortable because it was too accurate. Maybe someone named something you didn''t want acknowledged, or they saw you more clearly than you were ready for. What did they say, and why did it land so hard?', NULL, '{}', 'discomfort', 'feeling', '{answered_5+}', 'accurate_compliment', '{discomfort,truth}', 268),
(2, 'Think about a talent or ability {person_name} has that not enough people appreciate. Maybe they''re brilliant at something quiet, or they have a gift that doesn''t show up in obvious ways. What is it, and why do you wish more people could see it?', 'person', '{person_name}', 'admiration', 'people', '{has_contacts,answered_5+}', 'person_talent', '{admiration,recognition}', 269),
(2, 'Think about a place you and someone close always ended up at, no matter what the original plan was. Maybe it was a diner, a park, or a particular stretch of road. What drew you back, and what happened in that place that made it yours?', NULL, '{}', 'patterns', 'place', '{answered_5+}', 'default_place', '{patterns,comfort}', 270),
(2, 'Think about a time your body knew something before your mind caught up. Maybe your stomach dropped before bad news came, or your heart raced before you understood why. What was the situation, and how long did it take your thoughts to match your instincts?', NULL, '{}', 'intuition', 'feeling', '{answered_5+}', 'body_knowing', '{intuition,awareness}', 271),
(2, 'Think about a small thing you do every day that connects you to someone you love. Maybe it''s a text, a habit you share, or a ritual they''d recognize. What is it, and does the other person know how much it means to you?', NULL, '{}', 'ritual', 'event', '{answered_5+}', 'daily_connection', '{ritual,love}', 272),
(2, 'Think about the hardest {person_name} has ever laughed. Maybe it was a joke, a mishap, or something absurd that caught them off guard. What caused it, where were you, and what was it like to see them that undone with joy?', 'person', '{person_name}', 'joy', 'people', '{has_contacts,answered_5+}', 'person_laugh', '{joy,humor}', 273),
(2, 'Think about a lie you told that you still feel complicated about. Not a white lie, something with more weight. Maybe it protected someone, or maybe it just protected you. What was the lie, and what do you make of it now?', NULL, '{}', 'honesty', 'feeling', '{answered_5+}', 'complicated_lie', '{honesty,guilt}', 274),
(2, 'Think about a song {person_name} loved that you now can''t hear without thinking of them. Maybe it played at their house, in their car, or at a moment you shared. What''s the song, and what version of them does it bring back?', 'person', '{person_name}', 'music', 'object', '{has_contacts,answered_5+}', 'person_song', '{music,association}', 275),
(2, 'Think about a time you felt genuinely proud of someone else, not politely proud, but deeply moved by what they did. Maybe it was a child, a friend, or a parent stepping up. Who was it, what did they do, and what was that pride like in your chest?', NULL, '{}', 'pride', 'feeling', '{answered_5+}', 'proud_of_other', '{pride,love}', 276),
(2, 'Think about the hardest goodbye you''ve had to say more than once. Maybe it was a long-distance relationship, a recurring farewell at an airport, or a slow loss that kept asking you to let go again and again. What was it, and how did you carry it?', NULL, '{}', 'loss', 'event', '{answered_5+}', 'repeated_goodbye', '{loss,endurance}', 277),
(2, 'Think about a holiday that went completely off the rails and became better for it. Maybe the turkey burned, someone showed up unannounced, or plans fell apart in a way that brought people closer. What happened, and why was the chaos better than the plan?', NULL, '{}', 'holidays', 'event', '{answered_5+}', 'holiday_offscript', '{holidays,chaos,joy}', 278),
(2, 'Think about a lesson you learned from {person_name} that they never meant to teach. Maybe it was something about patience, honesty, or how to handle disappointment. What did you absorb just by watching them live their life?', 'person', '{person_name}', 'lessons', 'people', '{has_contacts,answered_5+}', 'person_accidental_lesson', '{lessons,modeling}', 279),
(2, 'Think about a time you forgave someone before you were truly ready. Maybe the situation called for it, or maybe you wanted to move forward even though the hurt was still fresh. How did it feel, and did the forgiveness eventually catch up to the decision?', NULL, '{}', 'forgiveness', 'turning_point', '{answered_5+}', 'early_forgiveness', '{forgiveness,process}', 280),
(2, 'Think about a community or group you belonged to that shaped you more than you expected. Maybe it was a church, a team, a neighborhood, or a group of coworkers. What was the group, what role did you play in it, and what did belonging there give you?', NULL, '{}', 'community', 'people', '{answered_5+}', 'shaping_community', '{community,identity}', 281),
(2, 'Think about a piece of art, music, or writing that said something you couldn''t put into words yourself. Maybe it captured a grief, a joy, or a longing that was yours but you had no language for. What was it, and what did it finally give voice to?', NULL, '{}', 'expression', 'object', '{answered_5+}', 'art_spoke', '{expression,resonance}', 282),
(2, 'Think about a time you sat with someone who was in pain and just being there was enough. You didn''t fix it, didn''t solve it, just stayed. Who was it, what were they going through, and what was it like to be the person who stayed?', NULL, '{}', 'presence', 'event', '{answered_5+}', 'sitting_with_pain', '{presence,compassion}', 283),
(2, 'Think about the place where you do your best thinking. Maybe it''s a porch, a trail, the shower, or a particular chair. What does it look like, what''s the view, and why does your mind open up there in a way it doesn''t elsewhere?', NULL, '{}', 'reflection', 'place', '{answered_5+}', 'thinking_spot', '{reflection,solitude}', 284),
(2, 'Think about a moment you chose kindness when it would have been easier not to. Maybe you were tired, hurt, or justified in being harsh. What made you choose the harder path, and did the other person know what it cost you?', NULL, '{}', 'character', 'event', '{answered_5+}', 'chose_kindness', '{character,integrity}', 285),
(2, 'Think about a secret you and {person_name} share that still makes you smile. Maybe it''s harmless, maybe it''s a little mischievous, but it''s yours. What is it, and what does having that shared secret mean about your bond?', 'person', '{person_name}', 'secrets', 'people', '{has_contacts,answered_5+}', 'person_secret', '{secrets,bonding}', 286),
(2, 'Think about a time you saw your parent not as your parent but as a person with their own fears, dreams, and heartbreaks. Maybe they told you something about their past, or you caught a look on their face that showed you something new. What did you see?', NULL, '{}', 'family', 'turning_point', '{answered_5+}', 'parent_as_person', '{family,empathy}', 287),
(2, 'Think about a scent that takes you immediately to a specific moment with a specific person. Maybe it''s their cologne, a food they made, or the air of a place you visited together. What is the scent, and where does it drop you?', NULL, '{}', 'sensory', 'feeling', '{answered_5+}', 'scent_person', '{sensory,association}', 288),
(2, 'Think about something you built, fixed, or made that solved a problem nobody else even saw. Maybe it was a system, a repair, or a creative workaround. What was the problem, what did you create, and what was satisfying about being the one who figured it out?', NULL, '{}', 'resourcefulness', 'object', '{answered_5+}', 'problem_solved', '{resourcefulness,creativity}', 289),
(2, 'Think about {person_name}''s handwriting. Maybe you''ve seen it on a card, a list, or a note left on the counter. What does it look like, and what does it tell you about them? Is it rushed, careful, messy, or distinctive in a way that feels like their personality on paper?', 'person', '{person_name}', 'detail', 'people', '{has_contacts,answered_5+}', 'person_handwriting', '{detail,character}', 290),
(2, 'Think about a time you put something in writing because you couldn''t say it out loud. Maybe it was a letter, a text, or something you wrote and never sent. What did you need to express, and why did writing feel safer than speaking?', NULL, '{}', 'expression', 'event', '{answered_5+}', 'written_not_spoken', '{expression,vulnerability}', 291),
(2, 'Think about a place you associate with a specific emotion, not a memory, an emotion. Maybe a hallway that feels like anticipation, a park that feels like grief, or a room that feels like safety. Where is it, and what emotion lives there for you?', NULL, '{}', 'association', 'place', '{answered_5+}', 'emotion_place', '{association,feeling}', 292),
(2, 'Think about the strangest coincidence that ever happened to you. Maybe two unrelated things converged in a way that felt like the universe was paying attention. What happened, and did it change how you think about chance?', NULL, '{}', 'fate', 'event', '{answered_5+}', 'strange_coincidence', '{fate,wonder}', 293),
(2, 'Think about a time someone''s face told you everything you needed to know before they spoke. Maybe it was joy, heartbreak, guilt, or relief. Whose face was it, what were you expecting, and what did their expression reveal?', NULL, '{}', 'perception', 'people', '{answered_5+}', 'face_told_all', '{perception,truth}', 294),
(2, 'Think about a time you changed your mind in the middle of doing something, and that pivot ended up mattering. Maybe you turned the car around, rewrote a message, or backed out of a commitment at the last second. What made you shift, and what came of it?', NULL, '{}', 'pivots', 'turning_point', '{answered_5+}', 'mid_pivot', '{pivots,courage}', 295),
(2, 'Think about a gift {person_name} gave you that was so perfect it almost hurt. Maybe it meant they''d been paying attention, remembering something you barely mentioned, or knowing you in a way that felt almost too close. What was the gift, and what did it say?', 'person', '{person_name}', 'gifts', 'object', '{has_contacts,answered_5+}', 'person_gift', '{gifts,being_known}', 296),
(2, 'Think about a neighborhood sound from your past that would unlock a flood of memories if you heard it now. Maybe it''s an ice cream truck, a specific bird, a factory whistle, or children playing. What is the sound, and what comes rushing back?', NULL, '{}', 'sensory', 'feeling', '{answered_5+}', 'neighborhood_sound', '{sensory,nostalgia}', 297),
(2, 'Think about an heirloom or family object that carries more weight than its size suggests. Maybe it''s a ring, a photograph, a tool, or a piece of furniture. What is it, who did it belong to, and what story does it hold that you don''t want lost?', NULL, '{}', 'heritage', 'object', '{answered_5+}', 'family_heirloom', '{heritage,weight}', 298),
(2, 'Think about a time someone showed you grace when you didn''t deserve it. Maybe you''d made a mistake, let someone down, or done something you''re not proud of. Who extended the grace, what form did it take, and what did it do to you?', NULL, '{}', 'grace', 'feeling', '{answered_5+}', 'undeserved_grace', '{grace,humility}', 299),
(2, 'Think about the most alive you''ve ever seen {person_name}. Maybe they were in their element, laughing hard, doing something they love, or completely absorbed in a moment. What were they doing, and what was it like to watch them be that fully themselves?', 'person', '{person_name}', 'vitality', 'people', '{has_contacts,answered_5+}', 'person_alive', '{vitality,essence}', 300),
(2, 'Think about a sound from nature that has personal meaning for you. Maybe it''s rain on a specific roof, waves at a beach you know, or wind through a particular kind of tree. What is the sound, and what moment or feeling does it carry?', NULL, '{}', 'nature', 'feeling', '{answered_5+}', 'nature_sound', '{nature,meaning}', 301),
(2, 'Think about a boundary you set that changed a relationship for the better. Maybe it was hard to draw, the other person didn''t like it at first, or you were afraid of what it would cost. What was the boundary, and how did things shift once it was in place?', NULL, '{}', 'boundaries', 'turning_point', '{answered_5+}', 'healthy_boundary', '{boundaries,growth}', 302),
(2, 'Think about a moment of public embarrassment that somehow turned into something wonderful. Maybe the attention shifted, someone came to your rescue, or the mistake opened a door you didn''t expect. What happened, and how did it turn around?', NULL, '{}', 'embarrassment', 'event', '{answered_5+}', 'embarrassment_win', '{embarrassment,redemption}', 303),
(2, 'Think about the last conversation with {person_name} that really mattered. Not small talk, but something with weight. What were you talking about, what was at stake, and did you both walk away feeling like something had been settled or opened up?', 'person', '{person_name}', 'depth', 'people', '{has_contacts,answered_5+}', 'person_deep_talk', '{depth,connection}', 304),
(2, 'Think about a color you associate with a specific time in your life. Maybe your college years were blue, your thirties were gold, or a certain summer was green. What''s the color, what''s the era, and what connects them in your mind?', NULL, '{}', 'synesthesia', 'feeling', '{answered_5+}', 'era_color', '{synesthesia,association}', 305),
(2, 'Think about a ritual that keeps you grounded, something you do in the morning, the evening, or with the changing seasons. What is it, how did it start, and what would be missing from your life if you stopped doing it?', NULL, '{}', 'ritual', 'event', '{answered_5+}', 'grounding_ritual', '{ritual,stability}', 306),
(2, 'Think about the most beautiful speaking voice you''ve ever heard. Not a singer, just someone talking. Maybe it was the tone, the pace, or the way they shaped their words. Whose voice was it, and what was it like to listen to them?', NULL, '{}', 'beauty', 'people', '{answered_5+}', 'beautiful_voice', '{beauty,presence}', 307),
(2, 'Think about a time someone you barely knew showed up for you in a big way. Maybe they offered help, said something you needed to hear, or made a gesture that carried real weight. Who were they, what did they do, and did you ever get to thank them properly?', NULL, '{}', 'unexpected', 'people', '{answered_5+}', 'acquaintance_showed_up', '{unexpected,kindness}', 308),
(2, 'Think about a physical sensation, warmth, cold, wind, water, that triggers a specific memory when you feel it. Maybe it''s the sun on your face that takes you somewhere, or cold air that drops you into a particular winter. What''s the sensation, and where does it put you?', NULL, '{}', 'sensory', 'feeling', '{answered_5+}', 'physical_trigger', '{sensory,memory}', 309),
(2, 'Think about a situation where you had to be the strong one. Maybe everyone was falling apart, someone needed you to hold it together, or there simply wasn''t anyone else. What did being strong look like, and what did it cost you afterward?', NULL, '{}', 'strength', 'event', '{answered_5+}', 'being_strong', '{strength,cost}', 310),
(2, 'Think about a time you and {person_name} didn''t need to say anything. Just being in the same room, the same car, the same space was enough. What were you doing, where were you, and what made the silence feel full instead of empty?', 'person', '{person_name}', 'presence', 'people', '{has_contacts,answered_5+}', 'person_presence', '{presence,comfort}', 311),
(2, 'Think about a scene from your life that could be a painting. Maybe it''s the way light fell on a kitchen table, a figure standing in a doorway, or a landscape you stood in at exactly the right moment. What would the painting show, and what would the title be?', NULL, '{}', 'beauty', 'place', '{answered_5+}', 'painting_scene', '{beauty,composition}', 312),
(2, 'Think about a time your intuition saved you from something. Maybe you changed plans at the last minute, trusted a gut feeling, or avoided something without a logical reason. What was the situation, and what would have happened if you''d ignored the feeling?', NULL, '{}', 'intuition', 'event', '{answered_5+}', 'intuition_saved', '{intuition,trust}', 313),
(2, 'Think about a time someone treated you as their safe place. They came to you when they were scared, confused, or hurting, and you were the one they chose. Who was it, what did they need, and what was it like to be that person for someone?', NULL, '{}', 'caregiving', 'feeling', '{answered_5+}', 'safe_place', '{caregiving,responsibility}', 314),
(2, 'Think about the most meaningful thing you''ve inherited, not necessarily the most expensive or impressive. Maybe it''s a recipe card, a watch, a quilt, or a habit. What is it, who did it come from, and what does it carry that money couldn''t buy?', NULL, '{}', 'inheritance', 'object', '{answered_5+}', 'meaningful_inheritance', '{inheritance,legacy}', 315),
(2, 'Think about a day that started completely ordinary and became unforgettable by the time it ended. What were you expecting, what actually happened, and at what point did you realize the day had turned into something else entirely?', NULL, '{}', 'surprise', 'event', '{answered_5+}', 'ordinary_to_unforgettable', '{surprise,fate}', 316),
(2, 'Think about the thing {person_name} does that tells you they love you without ever saying it. Maybe it''s how they make sure you eat, how they check the locks, or a look they give you across a room. What''s their love language in action?', 'person', '{person_name}', 'love_language', 'people', '{has_contacts,answered_5+}', 'person_love_language', '{love_language,actions}', 317),
(2, 'Think about a conversation that changed the direction of your career or your life. Maybe it happened in an office, over dinner, or with a stranger. What was said, who said it, and did you know in the moment that it was going to matter?', NULL, '{}', 'pivots', 'event', '{answered_5+}', 'direction_convo', '{pivots,influence}', 318),
(2, 'Think about a texture that brings back a memory when you touch it. Maybe it''s a certain fabric, the grain of a wooden table, or cool stone under your hands. What is the texture, where were you, and what were you feeling the last time it mattered?', NULL, '{}', 'sensory', 'feeling', '{answered_5+}', 'texture_memory', '{sensory,touch}', 319),
(2, 'Think about a time you let go of what you wanted so someone else could have what they needed. Maybe it was a sacrifice you chose, a dream you set aside, or a path you stepped off to make room. What did you give up, and was it worth it?', NULL, '{}', 'sacrifice', 'turning_point', '{answered_5+}', 'letting_go', '{sacrifice,love}', 320),
(2, 'Think about a time {person_name} stood up for you. Maybe it was public, maybe it was quiet, maybe they had something to lose by doing it. What happened, did they know how much it meant, and what did their defense tell you about who they are?', 'person', '{person_name}', 'defense', 'people', '{has_contacts,answered_5+}', 'person_stood_up', '{defense,loyalty}', 321),
(2, 'Think about a door in your life, literal or figurative, that you''re glad you walked through even though you were nervous. Maybe it was a move, a conversation, or a first step into something unknown. What was on the other side, and how different would things be if you''d stayed put?', NULL, '{}', 'decisions', 'turning_point', '{answered_5+}', 'glad_walked_through', '{decisions,courage}', 322),
(2, 'Think about a night sky you remember. Maybe you were on a camping trip, a rooftop, or standing in a field. Where were you, who was with you, and what were you thinking about while you looked up?', NULL, '{}', 'nature', 'place', '{answered_5+}', 'night_sky', '{nature,wonder}', 323),
(2, 'Think about the bravest thing you''ve ever said to someone. Maybe it was a truth you''d been holding back, a confession, or words that could have changed everything. What did you say, who did you say it to, and what happened in the silence afterward?', NULL, '{}', 'courage', 'event', '{answered_5+}', 'bravest_words', '{courage,truth}', 324),
(2, 'Think about a time helping someone changed you more than it changed them. Maybe the act of giving opened something, or you saw yourself differently through their eyes. What did you do, and what shifted in you as a result?', NULL, '{}', 'service', 'event', '{answered_5+}', 'helping_changed_me', '{service,transformation}', 325),
(2, 'Think about an object from {person_name} that you still keep close. Maybe it''s a letter, a tool, a piece of jewelry, or something they''d be surprised you saved. What is it, where do you keep it, and what does holding it feel like?', 'person', '{person_name}', 'keepsakes', 'object', '{has_contacts,answered_5+}', 'person_keepsake', '{keepsakes,connection}', 326),
(2, 'Think about a time you realized you were repeating a pattern from your family. Maybe it was how you argued, how you showed love, or how you handled stress. When did you notice the echo, and did you decide to keep it or break it?', NULL, '{}', 'patterns', 'turning_point', '{answered_5+}', 'family_pattern', '{patterns,awareness}', 327),
(2, 'Think about a time laughter broke the tension when nothing else could. Maybe it was a funeral, an argument, or a terrifying moment. What made everyone laugh, and what did the laughter do to the room?', NULL, '{}', 'humor', 'event', '{answered_5+}', 'laughter_rescue', '{humor,relief}', 328),
(2, 'Think about a moment of beauty you witnessed that felt like it was just for you. Maybe nobody else was around, or nobody else seemed to notice. What did you see, and what was it like to hold that beauty without sharing it?', NULL, '{}', 'wonder', 'feeling', '{answered_5+}', 'private_beauty', '{wonder,presence}', 329),
(2, 'Think about a mundane errand that turned into an adventure because of who you were with. Maybe it was grocery shopping, running to the hardware store, or doing something completely boring that became memorable. What happened, and who made it fun?', NULL, '{}', 'companionship', 'event', '{answered_5+}', 'errand_adventure', '{companionship,spontaneity}', 330),
(2, 'Think about what {person_name} smelled like. Not a perfume or cologne, but their actual presence, their house, their car, the air around them. What was the scent, and what feelings does it bring back when you remember it?', 'person', '{person_name}', 'sensory', 'feeling', '{has_contacts,answered_5+}', 'person_scent', '{sensory,intimacy}', 331),
(2, 'Think about a question a child asked you that stopped you in your tracks. Maybe it was simple, profound, or accidentally brilliant. What did they ask, what did you say, and what would you say now if you could answer more honestly?', NULL, '{}', 'children', 'event', '{answered_5+}', 'child_question', '{children,wisdom}', 332),
(2, 'Think about a time you chose to be vulnerable and it changed the dynamic of a relationship entirely. Maybe you admitted something, asked for help, or let someone see you without your armor. What happened, and how did the other person respond?', NULL, '{}', 'vulnerability', 'turning_point', '{answered_5+}', 'chose_vulnerable', '{vulnerability,change}', 333),
(2, 'Think about a time you drove or walked somewhere just to clear your head. Where did you go, what was spinning in your mind, and did the movement help? Sometimes the body needs to process what the mind can''t. What was going on?', NULL, '{}', 'processing', 'event', '{answered_5+}', 'clearing_head', '{processing,movement}', 334),
(2, 'Think about a word or phrase that only makes sense between you and someone you love. Maybe it came from a joke, a mishearing, or a private moment. What is it, how did it start, and what does it mean to have language that belongs only to the two of you?', NULL, '{}', 'language', 'people', '{answered_5+}', 'private_language', '{language,intimacy}', 335),
(2, 'Think about the most peaceful sound you can imagine. Maybe it''s something from nature, a person breathing, or a specific kind of quiet. What is it, and when was the last time you actually heard it? What would it take to hear it again?', NULL, '{}', 'peace', 'feeling', '{answered_5+}', 'peaceful_sound', '{peace,sensory}', 336),
(2, 'Think about a time someone you looked up to let you down. Maybe they made a mistake, showed a side of themselves you hadn''t seen, or simply turned out to be human. What happened, how did you handle it, and did you ever see them the same way again?', NULL, '{}', 'disillusion', 'people', '{answered_5+}', 'let_down', '{disillusion,maturity}', 337),
(2, 'Think about an old map, ticket, receipt, or stub you saved without really knowing why. Maybe it''s in a drawer, a box, or between the pages of a book. What is it, what does it mark, and what would you lose if you finally threw it away?', NULL, '{}', 'artifacts', 'object', '{answered_5+}', 'saved_artifact', '{artifacts,nostalgia}', 338),
(2, 'Think about a conversation with {person_name} that you wish had gone differently. Maybe you said the wrong thing, held back when you should have spoken, or missed a chance to be honest. What would you change, and what do you think the different version would have opened up?', 'person', '{person_name}', 'regret', 'people', '{has_contacts,answered_5+}', 'person_wish_convo', '{regret,honesty}', 339),
(2, 'Think about a tradition that ended. Maybe it faded naturally, someone who held it together moved away, or life just shifted. What was the tradition, what killed it, and should someone try to bring it back?', NULL, '{}', 'endings', 'event', '{answered_5+}', 'ended_tradition', '{endings,reflection}', 340),
(2, 'Think about the furthest you''ve ever felt from home. Maybe it was miles, or maybe it was a feeling that happened while sitting in your own kitchen. What created the distance, and what, if anything, eventually brought you back?', NULL, '{}', 'distance', 'feeling', '{answered_5+}', 'far_from_home', '{distance,loneliness}', 341),
(2, 'Think about the moment you realized you were no longer the younger generation. Maybe a reference went over someone''s head, you caught yourself saying something your parents would say, or a milestone hit you differently. What was the moment, and how did it feel?', NULL, '{}', 'aging', 'turning_point', '{answered_5+}', 'generational_shift', '{aging,perspective}', 342),
(2, 'Think about a meal you remember not for the food but for what happened around the table. Maybe it was a conversation, a revelation, an argument, or an unexpected guest. Who was there, what unfolded, and why does the dinner stay with you?', NULL, '{}', 'food', 'event', '{answered_5+}', 'table_event', '{food,gathering}', 343),
(2, 'Think about a way you''ve been misunderstood that still bothers you. Maybe people assume something about you that isn''t true, or a version of your story circulates that misses the point. What''s the misunderstanding, and what would you correct if you could?', NULL, '{}', 'identity', 'feeling', '{answered_5+}', 'misunderstood', '{identity,frustration}', 344),
(2, 'Think about a garden, a park, or a piece of land that holds meaning in your life. Maybe you planted it, walked it, or grew up beside it. What is the place, what happened there, and what does the earth itself represent to you?', NULL, '{}', 'nature', 'place', '{answered_5+}', 'meaningful_land', '{nature,roots}', 345),
(2, 'Think about a time you held someone''s hand and both of you knew exactly what it meant. Maybe it was comfort, a promise, a goodbye, or a beginning. Whose hand was it, where were you, and what passed between you without words?', NULL, '{}', 'touch', 'event', '{answered_5+}', 'hand_holding', '{touch,understanding}', 346),
(2, 'Think about a time you had to be the one to say the thing nobody else would say. Maybe the room was avoiding it, people were tiptoeing, or someone had to speak the truth. What did you say, and what happened after the words landed?', NULL, '{}', 'courage', 'event', '{answered_5+}', 'hard_truth_teller', '{courage,honesty}', 347),
(2, 'Think about the most comforting thing anyone has ever said to you during a hard time. Maybe it wasn''t profound or clever. Maybe it was simple and exactly right. What were the words, who said them, and what did they give you that you needed?', NULL, '{}', 'comfort', 'feeling', '{answered_5+}', 'comforting_words', '{comfort,care}', 348),
(2, 'Think about a time you caught yourself becoming someone you didn''t want to be. Maybe it was a pattern, a reaction, or a role you''d slipped into without noticing. What did you see, what triggered the awareness, and what did you do about it?', NULL, '{}', 'self_awareness', 'turning_point', '{answered_5+}', 'caught_myself', '{self_awareness,course_correction}', 349),
(2, 'Think about a lucky break that changed your life. Maybe it was a chance meeting, perfect timing, or an opportunity that appeared from nowhere. What happened, and how different would things be if that piece of luck hadn''t fallen into place?', NULL, '{}', 'fortune', 'event', '{answered_5+}', 'lucky_break', '{fortune,gratitude}', 350);
INSERT INTO prompt_seed_library (tier, text, anchor, placeholders, category, angle, requires, anti_repeat_group, snowball_hooks, sort_order) VALUES
(3, 'You shared something about {memory_theme} earlier. Think about whether there was a part of that story you held back, maybe a detail that felt too raw, a person you left out, or a feeling you skipped over. What''s the rest of it?', NULL, '{memory_theme}', 'deeper', 'feeling', '{answered_10+}', 'held_back', '{depth,honesty}', 351),
(3, 'If you could relive one ordinary Tuesday from about ten years ago, think about which one it would be. Not a special occasion, just a regular day when things felt right. What made it ordinary, and what made it perfect?', NULL, '{}', 'nostalgia', 'event', '{answered_10+}', 'ordinary_tuesday', '{nostalgia,specificity}', 352),
(3, 'Think about a question you wish someone would ask you. Maybe nobody has thought to ask it, or maybe you''ve been waiting for the right person to bring it up. What is the question, and what would your answer be?', NULL, '{}', 'unspoken', 'feeling', '{answered_10+}', 'wish_asked', '{unspoken,longing}', 353),
(3, 'Think about the thing you''re most afraid of losing, not a person, but a quality or ability. Maybe it''s your independence, your memory, your sense of humor, or your ability to connect. What is it, and what does the fear of losing it tell you about what matters most?', NULL, '{}', 'fear', 'feeling', '{answered_10+}', 'afraid_losing_quality', '{fear,identity}', 354),
(3, 'Think about a version of yourself that you had to leave behind to become who you are now. Maybe it was the people-pleaser, the perfectionist, or the person who played it safe. Who were they, and do you ever miss them?', NULL, '{}', 'evolution', 'turning_point', '{answered_10+}', 'former_self', '{evolution,shedding}', 355),
(3, 'Think about a conversation you keep almost having but never quite get to. Maybe you start it in your head, think about bringing it up, then let the moment pass. Who is it with, what needs to be said, and what keeps stopping you?', NULL, '{}', 'avoidance', 'feeling', '{answered_10+}', 'almost_conversation', '{avoidance,courage}', 356),
(3, 'When you''re alone with your thoughts at two in the morning, where does your mind go? Think about the usual territory. Is it worry, regret, planning, or something else? What comes to visit in the quiet, and how do you handle it?', NULL, '{}', 'introspection', 'feeling', '{answered_10+}', 'late_night_mind', '{introspection,worry}', 357),
(3, 'Think about a truth about your childhood that took you years to understand. Maybe you didn''t have the context as a kid, or maybe someone finally told you the real story. What was the truth, when did it land, and how did it change what you thought you knew?', NULL, '{}', 'childhood', 'turning_point', '{answered_10+}', 'childhood_truth', '{childhood,revelation}', 358),
(3, 'Think about the difference between who you are and who people think you are. Maybe the public version is more confident, more together, or simpler. What''s the gap, and what would it take for someone to see the full picture?', NULL, '{}', 'identity', 'feeling', '{answered_10+}', 'public_private', '{identity,mask}', 359),
(3, 'Think about a sacrifice someone made for you that you can never fully repay. Maybe it was time, opportunity, money, or something less tangible. Who made it, what did it cost them, and how do you carry the weight of that gift?', NULL, '{}', 'gratitude', 'people', '{answered_10+}', 'unrepayable', '{gratitude,debt}', 360),
(3, 'Think about the memory you return to most often. Maybe it''s comforting, unresolved, or just magnetic. What is it, how many times have you revisited it, and has the meaning changed over the years, even though the facts haven''t?', NULL, '{}', 'recurring', 'feeling', '{answered_10+}', 'most_revisited', '{recurring,interpretation}', 361),
(3, 'Think about the thing you''ve worked hardest to forgive. Maybe it''s a person, a situation, or yourself. What happened, how long did the process take, and where are you with it now? Is the forgiveness complete, or still in progress?', NULL, '{}', 'forgiveness', 'feeling', '{answered_10+}', 'hard_forgiveness', '{forgiveness,process}', 362),
(3, 'Think about a part of your story that shaped you more than anyone realizes. Maybe it happened quietly, or maybe you''ve never talked about it. What is it, and what would people understand about you differently if they knew?', NULL, '{}', 'hidden', 'event', '{answered_10+}', 'hidden_shaper', '{hidden,influence}', 363),
(3, 'Look at your hands right now. Think about what they''ve done, what they''ve held, what they''ve built, and how they''ve changed. What stories do your hands carry, and what do they tell you about the life you''ve lived?', NULL, '{}', 'reflection', 'feeling', '{answered_10+}', 'looking_at_hands', '{reflection,aging,work}', 364),
(3, 'Think about what your younger self would make of your life right now. Would they be surprised, proud, confused, or relieved? What would you want to tell them, and what question would they ask that you''d struggle to answer?', NULL, '{}', 'perspective', 'feeling', '{answered_10+}', 'younger_self_view', '{perspective,assessment}', 365),
(3, 'Think about a wound that healed but left a mark you still feel. Not a physical scar, but an emotional one. Maybe it''s a betrayal, a loss, or a failure. The wound is closed, but what does the scar remind you of when it aches?', NULL, '{}', 'scars', 'feeling', '{answered_10+}', 'emotional_scar', '{scars,resilience}', 366),
(3, 'Think about the most important thing you''ve never said to someone who is still alive and reachable. Maybe the timing has never been right, or the words feel too heavy. What is it, who is it for, and what are you waiting for?', NULL, '{}', 'unsaid', 'people', '{answered_10+}', 'unsaid_living', '{unsaid,urgency}', 367),
(3, 'Think about a pattern you keep repeating even though you see it clearly. Maybe it''s a way of relating to people, a habit of self-sabotage, or a cycle you fall back into. What is the pattern, and what do you think is underneath it?', NULL, '{}', 'patterns', 'turning_point', '{answered_10+}', 'repeated_pattern', '{patterns,awareness}', 368),
(3, 'Think about what loneliness actually feels like for you. Not the word, the sensation. Maybe it shows up in your body, in a room, or at a specific time of day. Where do you feel it, and what triggers it most?', NULL, '{}', 'loneliness', 'feeling', '{answered_10+}', 'loneliness_sensation', '{loneliness,embodiment}', 369),
(3, 'Think about the most honest thing you could say about your relationship with your father. Not the polished version, the real one. Maybe it''s gratitude, resentment, confusion, or love that''s hard to articulate. What would that sentence be?', NULL, '{}', 'family', 'people', '{answered_10+}', 'father_honest', '{family,truth}', 370),
(3, 'Think about what your life looks like from the outside and then compare it to how it actually feels on the inside. Where''s the biggest gap? What do people assume about your life that misses the mark?', NULL, '{}', 'perception', 'feeling', '{answered_10+}', 'outside_vs_inside', '{perception,gap}', 371),
(3, 'Think about a joy in your life that feels too fragile to talk about. Maybe you''re afraid that naming it will jinx it, or that it''s too precious to expose. What is it, and what does protecting it cost you?', NULL, '{}', 'fragility', 'feeling', '{answered_10+}', 'fragile_joy', '{fragility,superstition}', 372),
(3, 'Think about the most honest thing you could say about your relationship with your mother. Let yourself go past the usual answer to the deeper one. What would that truth sound like if you said it plainly?', NULL, '{}', 'family', 'people', '{answered_10+}', 'mother_honest', '{family,truth}', 373),
(3, 'Think about something you pretend doesn''t affect you but actually does, deeply. Maybe it''s a comment someone made, a situation you''re in, or something about the way your life has gone. What is it, and why do you keep the impact hidden?', NULL, '{}', 'masks', 'feeling', '{answered_10+}', 'hidden_impact', '{masks,vulnerability}', 374),
(3, 'Think about what you would do differently if you knew absolutely no one was keeping score. If there were no judgments, no expectations, no audience. What would you change, start, or stop?', NULL, '{}', 'freedom', 'event', '{answered_10+}', 'no_score', '{freedom,authenticity}', 375),
(3, 'Think about a regret you''ve learned to carry without it crushing you. Maybe it took years, maybe it''s still heavy sometimes, but you''ve found a way to live alongside it. What is the regret, and how did you make peace with it?', NULL, '{}', 'regret', 'feeling', '{answered_10+}', 'carried_regret', '{regret,acceptance}', 376),
(3, 'If you could go back and witness one moment from your life as a fly on the wall, not to change it, just to see it from the outside, which moment would you choose? Maybe you want to see your own face, or understand what someone else was feeling. What would you watch?', NULL, '{}', 'observation', 'event', '{answered_10+}', 'fly_on_wall', '{observation,curiosity}', 377),
(3, 'Think about the most difficult thing about being truly known by someone. Not the joy of intimacy, the hard part. Maybe it''s losing your hiding places, being seen on bad days, or the fear that full knowledge leads to disappointment. What scares you about it?', NULL, '{}', 'intimacy', 'feeling', '{answered_10+}', 'being_known', '{intimacy,fear}', 378),
(3, 'Think about something you''re still grieving that the world thinks you should be over by now. Maybe it''s been years, maybe people have stopped asking, or maybe you hide it because the timeline doesn''t match expectations. What is it, and what does carrying it in silence feel like?', NULL, '{}', 'grief', 'feeling', '{answered_10+}', 'ongoing_grief', '{grief,timeline}', 379),
(3, 'Think about a choice you had to make where both options would cause pain. There was no clean answer, just two versions of loss. What was the dilemma, what did you choose, and what do you tell yourself about the path you left behind?', NULL, '{}', 'dilemma', 'event', '{answered_10+}', 'both_hurt', '{dilemma,impossible}', 380),
(3, 'Think about the most tender thing you''ve ever witnessed between two other people. Maybe it was a parent with a child, two old friends, or strangers being gentle with each other. What did you see, and what did it stir in you?', NULL, '{}', 'tenderness', 'people', '{answered_10+}', 'witnessed_tender', '{tenderness,beauty}', 381),
(3, 'Think about a part of your body that carries a memory. Maybe your shoulders hold the weight of a certain year, your hands remember a specific kind of work, or your stomach knows a certain kind of dread. Where is the memory stored, and what does your body remember?', NULL, '{}', 'embodiment', 'feeling', '{answered_10+}', 'body_memory', '{embodiment,somatic}', 382),
(3, 'Think about what you would tell the next generation about what your era was really like. Not the headlines, but the texture of daily life, the fears, the joys, the things that mattered that nobody documented. What do you want them to know?', NULL, '{}', 'legacy', 'event', '{answered_10+}', 'era_truth', '{legacy,witness}', 383),
(3, 'Think about a door you closed that you sometimes wonder about opening again. Maybe it''s a career, a relationship, a place, or a version of yourself. What did you walk away from, and what draws you back in your imagination?', NULL, '{}', 'roads', 'feeling', '{answered_10+}', 'closed_door', '{roads,wonder}', 384),
(3, 'Think about what courage looks like in your everyday life. Not the dramatic, movie kind, but the quiet kind. Maybe it''s having a conversation you dread, showing up when you''d rather hide, or being honest when it''s easier to let it go. What does your daily bravery look like?', NULL, '{}', 'courage', 'event', '{answered_10+}', 'quiet_courage', '{courage,daily}', 385),
(3, 'Think about a moment when you felt completely understood, no explanation needed. Maybe someone just knew, or you found yourself in a conversation where everything clicked. Who was it, what was the context, and what did it feel like to not have to translate yourself?', NULL, '{}', 'connection', 'feeling', '{answered_10+}', 'understood', '{connection,relief}', 386),
(3, 'Think about what your life would have been like if you had stayed in {place}. Maybe you''d have different friends, a different career, or a completely different sense of self. What do you imagine, and does the imagined life look better, worse, or just different?', 'place', '{place}', 'alternate', 'turning_point', '{has_places,answered_10+}', 'what_if_stayed', '{alternate,imagination}', 387),
(3, 'Think about the heaviest secret you ever carried for someone else. Maybe they asked you to keep it, or you chose to protect them. What was the weight like, how long did you hold it, and what did carrying it do to you?', NULL, '{}', 'burden', 'event', '{answered_10+}', 'carried_secret', '{burden,loyalty}', 388),
(3, 'Think about a version of love you had to unlearn. Maybe it was love that looked like sacrifice, love that looked like control, or love that required you to disappear. What was the old model, and what does the healthier version look like?', NULL, '{}', 'love', 'turning_point', '{answered_10+}', 'unlearn_love', '{love,growth}', 389),
(3, 'Think about a time you surprised yourself with your own strength. Maybe you didn''t know you had it in you until the moment demanded it. What was the situation, what did you do, and how did it change the way you think about your own resilience?', NULL, '{}', 'strength', 'event', '{answered_10+}', 'surprised_strength', '{strength,revelation}', 390),
(3, 'Think about what you need more of in your life right now. Maybe it''s rest, connection, adventure, or honesty. What is it, and what''s standing between you and getting it? Is the obstacle real, or is it something you could move?', NULL, '{}', 'needs', 'feeling', '{answered_10+}', 'current_need', '{needs,obstacles}', 391),
(3, 'Think about a time you had to choose between being right and being kind. Maybe both felt important, and you could only pick one. What was the situation, which did you choose, and would you make the same call today?', NULL, '{}', 'compassion', 'event', '{answered_10+}', 'right_vs_kind', '{compassion,wisdom}', 392),
(3, 'Think about the most important thing about you that can''t be captured in a photograph. Maybe it''s how you make people feel, the quality of your attention, or something about your spirit that only shows up in motion. What is it?', NULL, '{}', 'essence', 'feeling', '{answered_10+}', 'beyond_photo', '{essence,spirit}', 393),
(3, 'Think about what {person_name} would say if they could see the person you''ve become. Maybe they''d be proud, surprised, or have questions. What do you imagine their reaction would be, and what would you most want them to notice?', 'person', '{person_name}', 'legacy', 'people', '{has_contacts,answered_10+}', 'person_would_say', '{legacy,approval}', 394),
(3, 'Think about the moment you realized your parents had full inner lives, worries, desires, and regrets that had nothing to do with you. Maybe they mentioned something from before you were born, or you saw them in a moment that was purely their own. When did that happen?', NULL, '{}', 'family', 'turning_point', '{answered_10+}', 'parents_inner_life', '{family,maturity}', 395),
(3, 'Think about what you know now about love that you couldn''t have understood at twenty. Maybe it''s about patience, about showing up, or about the difference between wanting someone and choosing them. What has experience taught you that youth simply couldn''t?', NULL, '{}', 'wisdom', 'feeling', '{answered_10+}', 'love_wisdom', '{wisdom,experience}', 396),
(3, 'Think about a moment of grace in your life that you rarely talk about because it feels too precious. Maybe sharing it would diminish it, or maybe you''re just protecting it. What was the moment, and what makes it sacred to you?', NULL, '{}', 'sacred', 'feeling', '{answered_10+}', 'precious_grace', '{sacred,protection}', 397),
(3, 'Think about the truest thing you know about yourself. Not the flattering thing or the self-critical thing, but the thing that is simply, undeniably true. What is it, and how long did it take you to see it clearly?', NULL, '{}', 'truth', 'feeling', '{answered_10+}', 'truest_self', '{truth,identity}', 398),
(3, 'Think about a way your life is richer than it looks from the outside. Maybe the visible markers don''t capture the depth of your relationships, the peace you''ve found, or the small pleasures that make your days full. What''s the hidden wealth?', NULL, '{}', 'hidden_wealth', 'feeling', '{answered_10+}', 'hidden_richness', '{hidden_wealth,gratitude}', 399),
(3, 'Think about the decade of life you''re in right now and what you''d want someone to understand about it. Maybe it''s not what you expected, harder in ways you didn''t predict, or more beautiful than people give it credit for. What''s the truth of this chapter?', NULL, '{}', 'era', 'feeling', '{answered_10+}', 'current_decade', '{era,truth}', 400),
(3, 'Think about a prayer, a wish, or a silent request you''ve been carrying. Maybe you direct it to God, the universe, or just the part of yourself that hopes. What are you asking for, and how long have you been asking?', NULL, '{}', 'spirit', 'feeling', '{answered_10+}', 'silent_prayer', '{spirit,hope}', 401),
(3, 'Think about a compliment you struggle to accept even though you suspect it''s true. Maybe someone calls you generous, creative, or strong, and part of you deflects. What''s the compliment, and why is it hard to let it in?', NULL, '{}', 'self_image', 'feeling', '{answered_10+}', 'hard_compliment', '{self_image,resistance}', 402),
(3, 'Think about the most peaceful you''ve ever been. Where were you, what were the conditions, who was nearby or absent? Try to reconstruct the ingredients of that peace. Could you ever recreate it, or was it a one-time alignment?', NULL, '{}', 'peace', 'feeling', '{answered_10+}', 'peak_peace', '{peace,conditions}', 403),
(3, 'Think about a conversation you''re avoiding because of what it might reveal. Maybe it would change a relationship, surface a truth, or ask something of you that you''re not sure you can give. What''s the conversation, and what are you protecting?', NULL, '{}', 'avoidance', 'feeling', '{answered_10+}', 'afraid_conversation', '{avoidance,truth}', 404),
(3, 'Think about something you''ve given up that you''re quietly mourning. Maybe nobody knows you miss it, or maybe you told yourself it was the right thing to let go. What was it, and what does the mourning feel like now that some time has passed?', NULL, '{}', 'mourning', 'feeling', '{answered_10+}', 'quiet_mourning', '{mourning,loss}', 405),
(3, 'Think about the gap between what you teach others and what you actually practice in your own life. Maybe you preach patience but struggle with it, or advocate for self-care but skip it yourself. Where''s the gap, and what does it tell you?', NULL, '{}', 'hypocrisy', 'feeling', '{answered_10+}', 'teach_vs_practice', '{hypocrisy,growth}', 406),
(3, 'Think about a boundary that took you the longest to learn. Maybe it''s about saying no, about protecting your time, or about what you''ll tolerate in a relationship. What was the boundary, what happened before you set it, and what changed after?', NULL, '{}', 'boundaries', 'turning_point', '{answered_10+}', 'slow_boundary', '{boundaries,self_respect}', 407),
(3, 'Think about what you''d do differently in your closest relationships if you had just a little more courage. Maybe you''d say something, ask for something, or stop pretending about something. What would change, and what holds you back?', NULL, '{}', 'courage', 'people', '{answered_10+}', 'relationship_courage', '{courage,vulnerability}', 408),
(3, 'Think about the question you''re most afraid to answer honestly. Maybe someone has asked it, or maybe it lives only in your own head. What is it, and what makes the honest answer feel so dangerous?', NULL, '{}', 'fear', 'feeling', '{answered_10+}', 'feared_question', '{fear,honesty}', 409),
(3, 'Think about what trust feels like in your body, not the concept but the physical sensation. Maybe it''s a softening in your shoulders, a loosening in your chest, or a feeling of warmth. Where does trust live in you, and when was the last time you felt it fully?', NULL, '{}', 'embodiment', 'feeling', '{answered_10+}', 'trust_in_body', '{embodiment,safety}', 410),
(3, 'Think about the most important thing you''ve learned about yourself in the last year. Maybe it came from a challenge, a relationship, or a quiet moment of clarity. What did you discover, and how has knowing it changed the way you move through your days?', NULL, '{}', 'growth', 'turning_point', '{answered_10+}', 'recent_lesson', '{growth,awareness}', 411),
(3, 'Think about something you want your loved ones to know about what this time in your life is really like. Maybe they see the surface but miss the undercurrents. What would you want them to understand, and why haven''t you said it yet?', NULL, '{}', 'truth', 'feeling', '{answered_10+}', 'this_time', '{truth,sharing}', 412),
(3, 'Think about what your face looks like when you think no one is watching. Maybe you''ve caught a glimpse in a window or someone has described it to you. What''s your default expression, and does it match how you feel inside?', NULL, '{}', 'awareness', 'feeling', '{answered_10+}', 'unguarded_face', '{awareness,default}', 413),
(3, 'Think about a moment you''d be embarrassed for anyone to know how much it meant to you. Maybe it seems small from the outside, or maybe caring that deeply feels vulnerable. What was the moment, and why does its importance feel like something to protect?', NULL, '{}', 'vulnerability', 'feeling', '{answered_10+}', 'secretly_important', '{vulnerability,shame}', 414),
(3, 'Think about a conversation you''re still having in your head with someone who isn''t here anymore. Maybe you talk to them while driving, argue with them in the shower, or tell them things that happened after they left. What do you say to them?', NULL, '{}', 'grief', 'people', '{answered_10+}', 'ongoing_convo', '{grief,continuation}', 415),
(3, 'Think about how you''ve become gentler over the years. Maybe it''s with other people, maybe with yourself, or maybe with life in general. What softened, when did it happen, and was there a specific moment that cracked the hard shell?', NULL, '{}', 'softening', 'turning_point', '{answered_10+}', 'becoming_gentler', '{softening,maturity}', 416),
(3, 'Think about a responsibility you carry that nobody asked you to take on. Maybe you appointed yourself the caretaker, the mediator, or the one who remembers. What is it, when did you pick it up, and what would happen if you set it down?', NULL, '{}', 'burden', 'feeling', '{answered_10+}', 'voluntary_burden', '{burden,duty}', 417),
(3, 'Think about what makes you feel most like yourself. Not a role, not a performance, just the purest version of who you are. Maybe it''s an activity, a person, a place, or a state of mind. What is it, and when was the last time you felt it?', NULL, '{}', 'identity', 'feeling', '{answered_10+}', 'most_myself', '{identity,authenticity}', 418),
(3, 'Think about a time you had to be brave for someone else even though you were terrified on the inside. Maybe you held someone''s hand during a crisis, gave a reassuring speech you didn''t believe, or kept your composure for a child. What was the situation, and where did you put your own fear?', NULL, '{}', 'bravery', 'event', '{answered_10+}', 'brave_for_other', '{bravery,selflessness}', 419),
(3, 'Think about the hardest part of getting older that nobody seems to talk about. Maybe it''s the invisible losses, the way time changes relationships, or the weight of accumulated experience. What has surprised you most, and what do you wish someone had warned you about?', NULL, '{}', 'aging', 'feeling', '{answered_10+}', 'aging_unspoken', '{aging,honesty}', 420),
(3, 'Think about your relationship with time right now. Do you have enough, too little, or the wrong kind? Maybe certain hours feel endless while years fly by. What does time feel like in this chapter of your life, and what would you do with more of it?', NULL, '{}', 'time', 'feeling', '{answered_10+}', 'time_relationship', '{time,urgency}', 421),
(3, 'Imagine a room with every person you''ve ever loved gathered inside. Think about what the energy would feel like. Would it be chaotic, warm, tense, joyful? Who would gravitate toward each other, and who would you want to stand near?', NULL, '{}', 'imagination', 'feeling', '{answered_10+}', 'love_gathering', '{imagination,love}', 422),
(3, 'Think about a story people tell about you that misses the point. Maybe the facts are right but the meaning is wrong, or an important detail always gets left out. What''s the real version, and what do you wish people understood about it?', NULL, '{}', 'truth', 'event', '{answered_10+}', 'misheard_story', '{truth,correction}', 423),
(3, 'Think about what you do with sadness when you can''t show it. Where does it go? Maybe you put it in your body, your work, your silence, or a habit nobody connects to grief. What''s your process, and does it actually help?', NULL, '{}', 'coping', 'feeling', '{answered_10+}', 'hidden_sadness', '{coping,processing}', 424),
(3, 'Think about the most clarifying moment of your life. A time when confusion suddenly became understanding, when a fog lifted and you could see clearly. What were you confused about, what triggered the clarity, and what did you do with the new understanding?', NULL, '{}', 'clarity', 'turning_point', '{answered_10+}', 'clarity_moment', '{clarity,epiphany}', 425),
(3, 'Think about a part of your heritage or culture that you''re still learning to understand. Maybe it''s complicated, maybe your feelings about it have evolved, or maybe you''re only now beginning to see its value. What is it, and where are you in the process?', NULL, '{}', 'heritage', 'feeling', '{answered_10+}', 'cultural_learning', '{heritage,identity}', 426),
(3, 'Think about something you want more credit for than you''ll ever ask for. Maybe it''s the emotional labor you do, the sacrifices nobody sees, or the way you hold things together quietly. What is it, and what would it mean to have it acknowledged?', NULL, '{}', 'recognition', 'feeling', '{answered_10+}', 'want_credit', '{recognition,pride}', 427),
(3, 'Think about a way you show love that isn''t always recognized as love. Maybe it looks like worry, like doing dishes, like giving space, or like being hard on someone because you want better for them. What''s your love in disguise?', NULL, '{}', 'love', 'event', '{answered_10+}', 'unrecognized_love', '{love,language}', 428),
(3, 'Think about what keeps you up at night. Not everyday anxiety, but the deeper questions. Maybe it''s about meaning, about whether you''re getting it right, or about what comes next. What are the big questions that visit you in the dark?', NULL, '{}', 'existential', 'feeling', '{answered_10+}', 'deep_night', '{existential,wonder}', 429),
(3, 'Think about something you''ve outgrown but still miss. Maybe it''s a friendship, a hobby, a way of being in the world, or a version of your life that no longer fits. What is it, and what do you miss most about the way things were?', NULL, '{}', 'outgrown', 'feeling', '{answered_10+}', 'outgrown_miss', '{outgrown,nostalgia}', 430),
(3, 'Think about a relationship that made you better at all your other relationships. Maybe it taught you patience, communication, or how to let someone in. Who was the person, what did the relationship look like, and what did you take from it into everything else?', NULL, '{}', 'growth', 'people', '{answered_10+}', 'relationship_teacher', '{growth,transfer}', 431),
(3, 'Think about the most important thing about your life that a biography would miss. Maybe it''s the quality of your inner world, the way you love quietly, or a feeling you carry that doesn''t translate into events and dates. What would be left out?', NULL, '{}', 'essence', 'feeling', '{answered_10+}', 'beyond_biography', '{essence,inner_life}', 432),
(3, 'Think about the thing you most want to protect in this world. Maybe it''s a person, a place, an idea, or a way of being. What is it, why does it matter to you, and what threatens it?', NULL, '{}', 'protection', 'feeling', '{answered_10+}', 'want_to_protect', '{protection,values}', 433),
(3, 'Think about what your life would sound like if it had a soundtrack. Would it be loud or quiet, fast or slow? Maybe different chapters would have different genres. What would be playing right now, and what song belongs to the most important scene?', NULL, '{}', 'creative', 'feeling', '{answered_10+}', 'life_soundtrack', '{creative,identity}', 434),
(3, 'Think about a time you received love in a form you didn''t recognize until later. Maybe someone was tough on you out of care, or they gave you space when you wanted closeness. What was the gesture, and when did you finally understand what it was?', NULL, '{}', 'love', 'feeling', '{answered_10+}', 'delayed_love', '{love,recognition}', 435),
(3, 'Think about the most generous interpretation of your hardest year. If you told the story with compassion for yourself instead of judgment, what would it sound like? What were you dealing with, and what did surviving it prove about who you are?', NULL, '{}', 'reframing', 'turning_point', '{answered_10+}', 'generous_interpretation', '{reframing,resilience}', 436),
(3, 'Think about what your silence communicates. When you go quiet, is it processing, protecting, withdrawing, or something else? What would someone need to understand about your silence to know what''s really going on?', NULL, '{}', 'communication', 'feeling', '{answered_10+}', 'silence_meaning', '{communication,inner_world}', 437),
(3, 'Think about a time you were loved in a way you didn''t feel you deserved. Maybe you were in a dark place, had made mistakes, or couldn''t give back equally. What was the love, who gave it, and what did accepting it do to you?', NULL, '{}', 'grace', 'feeling', '{answered_10+}', 'undeserved_love', '{grace,acceptance}', 438),
(3, 'If the walls of the house you grew up in could talk, think about what story they would tell. Not just yours, but the whole family''s. What happened in those rooms that shaped everyone who lived there? What would the walls know that nobody ever said out loud?', NULL, '{}', 'childhood', 'place', '{answered_10+}', 'walls_talking', '{childhood,home,secrets}', 439),
(3, 'Think about something you wish you could explain to the people who love you but can''t find the words for. Maybe it''s about how you process things, what you need, or what this particular stretch of life feels like from the inside. What would you say if language cooperated?', NULL, '{}', 'communication', 'feeling', '{answered_10+}', 'cant_explain', '{communication,frustration}', 440),
(3, 'Think about a time the world felt small in a beautiful way. Maybe you ran into someone unexpected, discovered a connection you didn''t know existed, or realized how linked everything is. What happened, and what did it make you feel about your place in things?', NULL, '{}', 'wonder', 'feeling', '{answered_10+}', 'small_world', '{wonder,connection}', 441),
(3, 'Think about the one thing about your inner life that would surprise the people closest to you. Maybe they think they know you fully, but there''s a room they haven''t entered. What''s in that room, and why have you kept it private?', NULL, '{}', 'hidden', 'feeling', '{answered_10+}', 'inner_surprise', '{hidden,depth}', 442),
(3, 'Think about what you''ve learned about loss that you wish you''d known before you experienced it. Maybe it''s about how grief works, what it asks of you, or how it changes shape without ever fully leaving. What do you know now?', NULL, '{}', 'loss', 'feeling', '{answered_10+}', 'loss_wisdom', '{loss,wisdom}', 443),
(3, 'Think about what home means to you now compared to what it meant when you were young. Maybe the definition has expanded, shifted, or become something you build rather than something you inherit. How has it changed?', NULL, '{}', 'evolution', 'feeling', '{answered_10+}', 'home_evolution', '{evolution,maturity}', 444),
(3, 'Think about what you would most want to hear from someone you''ve lost. Maybe it''s permission, forgiveness, a joke, or just their voice saying your name. What would they say, and what would those words give you?', NULL, '{}', 'grief', 'people', '{answered_10+}', 'want_to_hear', '{grief,longing}', 445),
(3, 'Think about the thing about you that has stayed the same no matter how much else has changed. Maybe it''s a value, a quirk, a way of seeing the world, or a need you''ve always had. What''s your constant, and are you glad it''s stayed?', NULL, '{}', 'core', 'feeling', '{answered_10+}', 'constant_self', '{core,identity}', 446),
(3, 'Think about a simple pleasure that has become almost sacred to you. Maybe it''s a morning cup of something, a walk, a weekly call, or a few minutes of quiet. What is it, and what happens inside you during that time that makes it feel essential?', NULL, '{}', 'sacred', 'event', '{answered_10+}', 'sacred_pleasure', '{sacred,routine}', 447),
(3, 'Think about the space between who you were and who you are now. Maybe it''s a canyon, maybe it''s a footbridge. How did you cross from one to the other, and is there anything from the old side that you brought with you?', NULL, '{}', 'integration', 'turning_point', '{answered_10+}', 'bridging_selves', '{integration,identity}', 448),
(3, 'Think about a way you''re still your parents'' child, no matter how old you get. Maybe it''s how you react under pressure, what comforts you, or a habit you thought you''d outgrow. What''s the thread that still ties you to being someone''s kid?', NULL, '{}', 'family', 'people', '{answered_10+}', 'still_their_child', '{family,permanence}', 449),
(3, 'Think about the most important promise you''ve made, whether to yourself, to someone else, or to something bigger. What was the promise, when did you make it, and how has keeping it shaped the life you''re living?', NULL, '{}', 'promises', 'feeling', '{answered_10+}', 'important_promise', '{promises,commitment}', 450);
INSERT INTO prompt_seed_library (tier, text, anchor, placeholders, category, angle, requires, anti_repeat_group, snowball_hooks, sort_order) VALUES
(4, 'You''ve shared so many memories now. Think about the thread that runs through them all. Maybe it''s a person who keeps appearing, a feeling that recurs, or a value you keep circling back to. What connects your stories, and what does the pattern reveal?', NULL, '{}', 'synthesis', 'turning_point', '{answered_20+}', 'common_thread', '{synthesis,pattern}', 451),
(4, 'Think about what your grandchildren, or the next young people in your life, would need to know about you to really understand you. Not your resume, not your timeline, but the essential thing. What is it?', NULL, '{}', 'legacy', 'feeling', '{answered_20+}', 'grandchildren_know', '{legacy,essence}', 452),
(4, 'If your life were a book and you had to name this current chapter, what would the title be? Think about the theme of right now, the central tension or joy. What''s the chapter about, and how close are you to the end of it?', NULL, '{}', 'narrative', 'turning_point', '{answered_20+}', 'chapter_title', '{narrative,framing}', 453),
(4, 'Think about the story of your life that you tell yourself. Maybe it''s a story of overcoming, of searching, of building, or of holding on. Is that the truest version, or is there a more honest narrative underneath the one you''ve rehearsed?', NULL, '{}', 'narrative', 'feeling', '{answered_20+}', 'self_narrative', '{narrative,truth}', 454),
(4, 'If you could leave one sentence behind for someone to find in a hundred years, something that captures what you''ve learned, what would it say? Take your time with this one. What do you know that''s worth preserving?', NULL, '{}', 'legacy', 'feeling', '{answered_20+}', 'one_sentence', '{legacy,distillation}', 455),
(4, 'Think about the central lesson your life has been trying to teach you, the one that keeps showing up in different forms. Maybe you''ve resisted it, embraced it, or are still in the middle of learning it. What is it, and how has it appeared over the years?', NULL, '{}', 'wisdom', 'turning_point', '{answered_20+}', 'central_lesson', '{wisdom,pattern}', 456),
(4, 'If you were writing a memoir, what would the title be? Think about what captures the essence, not just the events but the feeling of your life. What phrase or image would tell someone the most about who you are?', NULL, '{}', 'identity', 'feeling', '{answered_20+}', 'memoir_title', '{identity,self_image}', 457),
(4, 'Imagine sitting across from your twenty-year-old self for an hour. Think about what you would tell them, what you would warn them about, and what reassurance they desperately need. What question do you think they would ask that would be hardest to answer?', NULL, '{}', 'dialogue', 'people', '{answered_20+}', 'younger_self_convo', '{dialogue,time}', 458),
(4, 'Think about the most important thing you''ve learned about being human. Not a lesson from a book, but something you earned through living. What is it, and how did experience teach you what theory couldn''t?', NULL, '{}', 'wisdom', 'feeling', '{answered_20+}', 'being_human', '{wisdom,universal}', 459),
(4, 'Think about what keeps you going on the days when nothing feels like enough. Maybe it''s a person, a promise, a habit, or just a stubborn refusal to stop. What is the thing that gets you out of bed when the reasons aren''t obvious?', NULL, '{}', 'resilience', 'feeling', '{answered_20+}', 'what_sustains', '{resilience,motivation}', 460),
(4, 'Think about what you want your life to have meant when you look at the whole of it. Not accomplishments, not status, but the actual mark you leave. What do you want the meaning to be?', NULL, '{}', 'purpose', 'feeling', '{answered_20+}', 'life_meaning', '{purpose,legacy}', 461),
(4, 'If someone made a movie of your life, think about the one scene you would insist they get exactly right. Maybe it''s a conversation, a moment of quiet, or a turning point that only you know the full weight of. What scene, and why that one?', NULL, '{}', 'pivotal', 'event', '{answered_20+}', 'must_get_right', '{pivotal,truth}', 462),
(4, 'After everything you''ve remembered and shared, think about the version of yourself that your loved ones will carry with them. Not the facts of your life, but the feeling of you. What do you hope they remember most? Is it something you said, something you did, or just a way you made them feel?', NULL, '{}', 'legacy', 'feeling', '{answered_20+}', 'remembered_for', '{legacy,love}', 463),
(4, 'Think about the question you would most want answered. Maybe it''s about your family''s past, about someone''s true feelings, or about what happens next. If you could know one thing with certainty, what would it be?', NULL, '{}', 'mystery', 'feeling', '{answered_20+}', 'unanswered_question', '{mystery,curiosity}', 464),
(4, 'Think about the kindest version of your own story. If you told your life with maximum compassion and minimum judgment, what would it sound like? What would you forgive yourself for, and what would you celebrate?', NULL, '{}', 'compassion', 'feeling', '{answered_20+}', 'kindest_version', '{compassion,self_love}', 465),
(4, 'Think about a contradiction in your personality that you''ve made peace with. Maybe you''re both shy and bold, both structured and chaotic, or both independent and deeply needy. What''s the contradiction, and how did you stop fighting it?', NULL, '{}', 'acceptance', 'feeling', '{answered_20+}', 'accepted_contradiction', '{acceptance,wholeness}', 466),
(4, 'Think about wisdom you''ve earned the hard way that you hope someone else can learn more gently. What did the experience cost you, what did it teach you, and how would you pass it on without making it sound like a lecture?', NULL, '{}', 'teaching', 'feeling', '{answered_20+}', 'hard_won_wisdom', '{teaching,generosity}', 467),
(4, 'Think about how much of your life has actually been about love, even the parts that didn''t look like it at the time. Maybe the tough decisions, the sacrifices, and the silent years were all driven by some form of love. What does the full picture look like through that lens?', NULL, '{}', 'love', 'feeling', '{answered_20+}', 'love_through_all', '{love,reframing}', 468),
(4, 'If someone only had five minutes with you and wanted to really understand who you are, what would you want them to know? Not your biography, but the essential truth. What''s the five-minute version of you?', NULL, '{}', 'essence', 'feeling', '{answered_20+}', 'five_minutes', '{essence,priority}', 469),
(4, 'If you could guarantee that your loved ones would understand one thing about your life, truly and fully, what would it be? Think about the thing you''ve struggled most to communicate. What is it, and why does it matter so much that they get it?', NULL, '{}', 'communication', 'feeling', '{answered_20+}', 'guarantee_understood', '{communication,legacy}', 470),
(4, 'Think about the line that connects the child you were to the person you are now. What has survived every change, every loss, every reinvention? Maybe it''s curiosity, stubbornness, tenderness, or something else entirely. What''s the throughline?', NULL, '{}', 'continuity', 'turning_point', '{answered_20+}', 'child_to_adult', '{continuity,identity}', 471),
(4, 'Think about what you expected life to be like and compare it with how it actually turned out. Where did reality fall short of the dream, where did it exceed it, and where did it go somewhere you never imagined? What surprises you most about the difference?', NULL, '{}', 'expectations', 'feeling', '{answered_20+}', 'expectations_vs_reality', '{expectations,acceptance}', 472),
(4, 'Think about the bravest thing about the way you''ve lived your life. Not a single moment, but the sustained courage of how you''ve shown up over decades. Maybe it''s choosing love, staying honest, or refusing to give up on something. What would you give yourself credit for?', NULL, '{}', 'courage', 'feeling', '{answered_20+}', 'bravest_life', '{courage,pride}', 473),
(4, 'Think about what you were put here to learn. Maybe you''ve figured it out, or maybe you''re still in the middle of the lesson. Is it patience, forgiveness, joy, how to let go, or something else? What does the curriculum of your life seem to be?', NULL, '{}', 'purpose', 'feeling', '{answered_20+}', 'here_to_learn', '{purpose,spiritual}', 474),
(4, 'You''ve shared memories that keep circling back to a few themes. Think about whether you can see a pattern you hadn''t noticed before. Maybe it''s about belonging, about independence, about showing up for people. What''s emerging that surprises you?', NULL, '{}', 'discovery', 'turning_point', '{answered_20+}', 'new_pattern', '{discovery,awareness}', 475),
(4, 'Think about someone going through what you went through, whatever the hardest part of your life was. If you could sit with them and speak from experience, what would you say? Not platitudes, but the honest, earned truth. What words would actually help?', NULL, '{}', 'advice', 'feeling', '{answered_20+}', 'hindsight_advice', '{advice,empathy}', 476),
(4, 'Think about the most important thing that almost didn''t happen. Maybe a relationship nearly missed, a decision almost made differently, or a stroke of luck that could easily have gone the other way. What was it, and what does your life look like without it?', NULL, '{}', 'fate', 'event', '{answered_20+}', 'almost_didnt', '{fate,gratitude}', 477),
(4, 'Think about how you want to be loved for the rest of your life. Maybe what you needed at twenty is different from what you need now. What does love look like in this chapter, and have you told anyone what you actually want?', NULL, '{}', 'love', 'feeling', '{answered_20+}', 'future_love', '{love,desire}', 478),
(4, 'Think about the question you keep circling back to, the one that won''t leave you alone no matter how many times you try to answer it. What is it, how long have you been carrying it, and are you any closer to an answer than when you started?', NULL, '{}', 'obsession', 'feeling', '{answered_20+}', 'recurring_question', '{obsession,meaning}', 479),
(4, 'Think about the most generous assumption someone could make about the life you''ve lived. If they looked at your choices, your struggles, and your path with the kindest possible eyes, what would they see? What story would generosity tell about you?', NULL, '{}', 'grace', 'feeling', '{answered_20+}', 'generous_assumption', '{grace,perspective}', 480),
(4, 'Think about what has surprised you most about the person you''ve become. Maybe younger you wouldn''t have predicted this job, this city, this way of being. What''s the biggest surprise, and are you pleased with it or still adjusting?', NULL, '{}', 'surprise', 'turning_point', '{answered_20+}', 'self_surprise', '{surprise,evolution}', 481),
(4, 'If you could only pass down three things to the next generation, not objects but truths, values, or ways of being, what would they be? Think about what matters enough to survive you. What three things would you want to outlast everything else?', NULL, '{}', 'legacy', 'feeling', '{answered_20+}', 'three_things', '{legacy,curation}', 482),
(4, 'Think about the most beautiful ordinary thing in your life right now. Not a vacation or a milestone, just a regular part of your days that, if you stop and notice it, is genuinely lovely. What is it, and when was the last time you paused to appreciate it?', NULL, '{}', 'gratitude', 'feeling', '{answered_20+}', 'beautiful_ordinary', '{gratitude,present}', 483),
(4, 'Think about the love letter you owe your own life. If you had to write a thank-you note to the whole messy, imperfect, surprising experience of being you, what would it say? What are you grateful for that you rarely name?', NULL, '{}', 'self_love', 'feeling', '{answered_20+}', 'love_letter_life', '{self_love,gratitude}', 484),
(4, 'Think about what you would want written on the last page of your story. Not an epitaph, but a closing line. Something that captures the tone, the lesson, or the feeling you want to leave behind. What sentence would end it right?', NULL, '{}', 'endings', 'feeling', '{answered_20+}', 'last_page', '{endings,meaning}', 485),
(4, 'Think about all the people you''ve loved and what they have in common. Maybe it''s a quality, a way of being, or something they all made you feel. What''s the pattern, and what does it tell you about what you''re drawn to and what you need?', NULL, '{}', 'patterns', 'people', '{answered_20+}', 'love_pattern', '{patterns,attraction}', 486),
(4, 'Think about what a good day looks like at this point in your life. Has the definition changed? Maybe it used to require excitement and now it requires stillness, or the other way around. What does a good day look like now, and what does that shift reveal?', NULL, '{}', 'evolution', 'event', '{answered_20+}', 'good_day_now', '{evolution,simplicity}', 487),
(4, 'Think about the thing you''ve built that you''re proudest of. Not a thing you can hold, but a life, a family, a reputation, a way of being in the world. What is it, how long has it taken, and what did it require of you?', NULL, '{}', 'pride', 'feeling', '{answered_20+}', 'proudest_built', '{pride,creation}', 488),
(4, 'Think about your relationship with hope and how it has changed over the years. Maybe you''re more hopeful now, or more cautious, or hope looks completely different than it used to. What does hope mean to you at this stage, and where do you find it?', NULL, '{}', 'hope', 'feeling', '{answered_20+}', 'hope_relationship', '{hope,evolution}', 489),
(4, 'Think about the song that would play over the closing credits of your life''s movie. What would it be, what mood would it set, and why does that song capture the feeling you want to leave behind? Would people be surprised by your choice?', NULL, '{}', 'music', 'feeling', '{answered_20+}', 'closing_song', '{music,tone}', 490),
(4, 'Think about what you still want to become. Not achieve, but become. Maybe it''s a quality you want to develop, a way of being you''re growing into, or a version of yourself that''s still taking shape. What is it, and what will it take to get there?', NULL, '{}', 'aspiration', 'feeling', '{answered_20+}', 'still_becoming', '{aspiration,future}', 491),
(4, 'Think about your greatest act of faith, religious or otherwise. Maybe it was trusting a person, taking a leap, or believing in something you couldn''t prove. What was the act, what were you risking, and how did it change you to take that step?', NULL, '{}', 'faith', 'event', '{answered_20+}', 'greatest_faith', '{faith,leap}', 492),
(4, 'Think about the part of your story that only you can tell. Maybe it''s a perspective nobody else has, a truth that lives inside your experience alone, or a piece of history that dies with you if you don''t share it. What is it, and what makes your telling essential?', NULL, '{}', 'uniqueness', 'feeling', '{answered_20+}', 'only_you', '{uniqueness,authority}', 493),
(4, 'Think about what you would want people in the future to know about what it was like to live in this time. Not the news, but the feeling of it. The small pleasures, the particular worries, the texture of daily life that won''t make it into history books. What would you preserve?', NULL, '{}', 'witness', 'event', '{answered_20+}', 'era_witness', '{witness,history}', 494),
(4, 'If your life had a thesis statement, a single argument it''s been making all along, what would it be? Think about the core message underneath all the noise, the changes, and the detours. What has your life been trying to say?', NULL, '{}', 'synthesis', 'feeling', '{answered_20+}', 'thesis_statement', '{synthesis,distillation}', 495),
(4, 'Think about the most important conversation you''ve ever had with yourself. Maybe it happened during a walk, in the mirror, or in the middle of the night. What did you need to tell yourself, and did you listen?', NULL, '{}', 'introspection', 'event', '{answered_20+}', 'self_conversation', '{introspection,growth}', 496),
(4, 'After everything, all the stories, the people, the places, the choices, think about what you know for sure. Not what you believe or hope, but what you know in your bones to be true. What is it?', NULL, '{}', 'certainty', 'feeling', '{answered_20+}', 'know_for_sure', '{certainty,wisdom}', 497),
(4, 'Think about the part of your life that has been the most unexpected gift. Maybe it''s something you never would have chosen, a detour that became the main road, or a person who arrived when the script said otherwise. What is the gift, and what makes it so remarkable?', NULL, '{}', 'gratitude', 'feeling', '{answered_20+}', 'unexpected_gift', '{gratitude,surprise}', 498),
(4, 'Think about what your life has actually been about. Not what it was supposed to be about, not the plan, but the real thing underneath all the plans. If you strip away the noise, the expectations, and the distractions, what was it really about?', NULL, '{}', 'truth', 'turning_point', '{answered_20+}', 'actually_about', '{truth,honesty}', 499),
(4, 'Close your eyes for a moment and think about all of it, your whole life, your whole story, everything you''ve remembered and everything still hidden. Don''t try to organize it or judge it. Just feel the weight and the warmth of it all. What do you feel?', NULL, '{}', 'summation', 'feeling', '{answered_20+}', 'final_feeling', '{summation,wholeness}', 500);
